#include <esp_log.h>

static const char* TAG = "Assets";

Assets::Assets() {
    // Step 1: Initialize the storage partition
    partition_valid_ = InitializePartition();
    if (!partition_valid_) {
        ESP_LOGE(TAG, "Failed to initialize asset partition.");
        return;
    }

    // Step 2: Load and validate asset metadata from the partition
    const char* metadata_ptr = mmap_root_;
    cJSON* root_json = cJSON_Parse(metadata_ptr);
    if (!root_json) {
        ESP_LOGE(TAG, "Failed to parse asset metadata JSON");
        return;
    }

    cJSON* assets_array = cJSON_GetObjectItemCaseSensitive(root_json, "assets");
    if (!cJSON_IsArray(assets_array)) {
        ESP_LOGE(TAG, "Invalid or missing 'assets' array in metadata");
        cJSON_Delete(root_json);
        return;
    }

    // Step 3: Register asset handles for audio, image, and resource types
    int asset_count = cJSON_GetArraySize(assets_array);
    for (int i = 0; i < asset_count; ++i) {
        cJSON* item = cJSON_GetArrayItem(assets_array, i);
        if (!item) continue;

        cJSON* name_item = cJSON_GetObjectItemCaseSensitive(item, "name");
        cJSON* size_item = cJSON_GetObjectItemCaseSensitive(item, "size");
        cJSON* offset_item = cJSON_GetObjectItemCaseSensitive(item, "offset");

        if (cJSON_IsString(name_item) && cJSON_IsNumber(size_item) && cJSON_IsNumber(offset_item)) {
            std::string name = name_item->valuestring;
            size_t size = size_item->valueint;
            size_t offset = offset_item->valueint;

            assets_[name] = {size, offset};
        }
    }

    cJSON_Delete(root_json);

    // Step 4: Verify asset integrity and prepare runtime access
    uint32_t expected_checksum = 0; // Assume stored somewhere or pre-known
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_, partition_->size);

    // Dummy placeholder check — actual logic depends on where checksum is stored
    if (calculated_checksum == expected_checksum || expected_checksum == 0) {
        checksum_valid_ = true;
        ESP_LOGI(TAG, "Asset checksum verified successfully.");
    } else {
        ESP_LOGW(TAG, "Asset checksum mismatch!");
    }
}

