Assets::~Assets() {
    // Step 1: Check if a valid memory-mapped partition handle exists
    if (mmap_handle_ != 0) {
        // Step 2: Unmap the partition and release associated resources
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0; // Reset handle to avoid reuse
    }

    // Step 3: Reset internal state to prevent invalid access or double-free
    mmap_root_ = nullptr;
    partition_ = nullptr;
    partition_valid_ = false;
    checksum_valid_ = false;

    // Optional: Clear any stored asset metadata if dynamically managed
    assets_.clear();

    // Note: models_list_ assumed to be managed separately or not owned directly here
}

#include <cstdint>

uint16_t CalculateChecksum(const char *data, uint32_t length) {
    uint32_t checksum = 0;

    // Iterate over each byte and accumulate the sum
    for (uint32_t i = 0; i < length; ++i) {
        checksum += static_cast<uint8_t>(data[i]);
    }

    // Mask to 16-bit value
    return static_cast<uint16_t>(checksum & 0xFFFF);
}

