bool Assets::InitializePartition() {
    // Step 1: Verify partition existence and minimum size requirements
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_UNDEFINED, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        return false;
    }

    if (partition_->size < sizeof(uint32_t)) { // At least big enough for checksum
        ESP_LOGE(TAG, "Assets partition too small");
        return false;
    }

    // Step 2: Map the partition into memory for direct access
    if (mmap_handle_ != 0) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }

    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Step 3: Perform checksum validation on the partition data
    const uint32_t stored_checksum = *reinterpret_cast<const uint32_t*>(mmap_root_);
    const char* data_start = mmap_root_ + sizeof(uint32_t);
    const uint32_t data_length = partition_->size - sizeof(uint32_t);

    uint32_t calculated_checksum = CalculateChecksum(data_start, data_length);
    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%08X, calculated=0x%08X", stored_checksum, calculated_checksum);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }
    checksum_valid_ = true;

    // Step 4: Build in-memory index of assets with size and offset metadata
    assets_.clear();

    cJSON* json = cJSON_Parse(data_start);
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse assets manifest JSON");
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }

    cJSON* assets_json = cJSON_GetObjectItemCaseSensitive(json, "assets");
    if (!cJSON_IsArray(assets_json)) {
        ESP_LOGE(TAG, "Invalid assets manifest: 'assets' array missing or invalid");
        cJSON_Delete(json);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }

    cJSON* asset_item;
    cJSON_ArrayForEach(asset_item, assets_json) {
        cJSON* name_item = cJSON_GetObjectItemCaseSensitive(asset_item, "name");
        cJSON* size_item = cJSON_GetObjectItemCaseSensitive(asset_item, "size");
        cJSON* offset_item = cJSON_GetObjectItemCaseSensitive(asset_item, "offset");

        if (!cJSON_IsString(name_item) || !cJSON_IsNumber(size_item) || !cJSON_IsNumber(offset_item)) {
            ESP_LOGW(TAG, "Skipping invalid asset entry in manifest");
            continue;
        }

        std::string name = name_item->valuestring;
        size_t size = size_item->valueint;
        size_t offset = offset_item->valueint;

        // Validate offset and size against partition bounds
        if (offset + size > data_length) {
            ESP_LOGW(TAG, "Asset '%s' out of bounds, skipping", name.c_str());
            continue;
        }

        assets_[name] = {size, offset};
    }

    cJSON_Delete(json);

    // Step 5: Set initialization flag and return success status
    partition_valid_ = true;
    return true;
}

