void Assets::Download(std::string url, std::function<void(int progress, size_t speed)> callback) {
    const size_t CHUNK_SIZE = 4096;
    std::vector<uint8_t> buffer(CHUNK_SIZE);

    auto start_time = high_resolution_clock::now();
    size_t total_downloaded = 0;
    int last_reported_progress = -1;

    // Step 1: Initialize HTTP connection
    HttpClient client(url);
    if (!client.connect()) {
        // Handle error
        return;
    }

    size_t content_length = client.getContentLength();
    if (content_length == 0 || !Board::isPartitionLargeEnough(content_length)) {
        client.disconnect();
        return; // Not enough space
    }

    // Step 2: Erase flash sectors needed for this asset
    FlashPartition partition = Board::getAssetPartition();
    if (!partition.erase(0, content_length)) {
        client.disconnect();
        return; // Failed to erase
    }

    // Step 3: Begin downloading and writing in chunks
    size_t offset = 0;
    while (total_downloaded < content_length) {
        size_t bytes_to_read = std::min(CHUNK_SIZE, content_length - total_downloaded);
        ssize_t read_bytes = client.read(buffer.data(), bytes_to_read);

        if (read_bytes <= 0)
            break;

        // Step 4: Write to flash
        if (!partition.write(offset, buffer.data(), read_bytes)) {
            client.disconnect();
            return; // Write failure
        }

        total_downloaded += read_bytes;
        offset += read_bytes;

        // Report progress every ~5%
        int progress = static_cast<int>((static_cast<float>(total_downloaded) / content_length) * 100);
        if (progress != last_reported_progress && (progress % 5 == 0 || progress >= 100)) {
            auto now = high_resolution_clock::now();
            duration<double> elapsed = now - start_time;
            size_t speed_bps = elapsed.count() > 0 ? static_cast<size_t>(total_downloaded / elapsed.count()) : 0;

            callback(progress, speed_bps);
            last_reported_progress = progress;
        }
    }

    client.disconnect();

    // Step 5: Finalize and verify
    if (total_downloaded != content_length) {
        return; // Incomplete download
    }

    // Optional: perform checksum validation
    if (!AssetValidator::verify(partition.getAddress(), content_length)) {
        return; // Checksum mismatch
    }

    partition.finalize(); // Commit changes if necessary
}

