bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const {
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    switch (from) {
        case DeviceState::kOff:
            return to == DeviceState::kInitializing;

        case DeviceState::kInitializing:
            return (to == DeviceState::kReady || to == DeviceState::kError);

        case DeviceState::kReady:
            return (to == DeviceState::kActive ||
                    to == DeviceState::kError ||
                    to == DeviceState::kShutdown);

        case DeviceState::kActive:
            return (to == DeviceState::kReady ||
                    to == DeviceState::kError ||
                    to == DeviceState::kShutdown);

        case DeviceState::kError:
            return to == DeviceState::kOff;

        case DeviceState::kShutdown:
            return to == DeviceState::kOff;

        default:
            // Undefined or unknown state transitions are not allowed
            return false;
    }
}

void DeviceStateMachine::TransitionTo(DeviceState targetState) {
    // Step 1: Validate the requested state transition
    if (!IsTransitionValid(_currentState, targetState)) {
        // Invalid transition - do nothing or log error depending on policy
        return;
    }

    // Step 2: Perform cleanup/exit actions for the current state
    OnExitState(_currentState);

    // Step 3: Save previous state and update to new state
    DeviceState previousState = _currentState;
    _currentState = targetState;

    // Step 4: Execute entry actions for the new state
    OnEnterState(targetState);

    // Step 5: Notify all registered observers about the state change
    NotifyObservers(previousState, targetState);
}

