    Ota();
};

Ota::Ota() {
    memset(serial_number_, 0, sizeof(serial_number_));

    // Step 1: Initialize eFuse (no explicit init needed in most cases)

    // Step 2: Read serial number from eFuse user data block
    uint8_t raw_serial[SERIAL_NUMBER_SIZE];
    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_USER_DATA_MAC_CUSTOM, raw_serial, SERIAL_NUMBER_SIZE * 8);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read serial number from eFuse: %s", esp_err_to_name(err));
        strncpy(serial_number_, "UNKNOWN_DEVICE", sizeof(serial_number_) - 1);
        return;
    }

    // Step 3: Validate serial number (check if all zeros or empty)
    bool is_valid = false;
    for (int i = 0; i < SERIAL_NUMBER_SIZE; ++i) {
        if (raw_serial[i] != 0x00) {
            is_valid = true;
            break;
        }
    }

    if (!is_valid) {
        ESP_LOGW(TAG, "Serial number read from eFuse is empty or invalid.");
        strncpy(serial_number_, "INVALID_SERIAL", sizeof(serial_number_) - 1);
        return;
    }

    // Step 4: Store valid serial number
    memcpy(serial_number_, raw_serial, SERIAL_NUMBER_SIZE);
    serial_number_[SERIAL_NUMBER_SIZE] = '\0'; // Ensure null termination

    ESP_LOGI(TAG, "Device serial number initialized: %s", serial_number_);
}

