    // Step 2: Read boolean value by key from NVS
    uint8_t value = 0;
    err = nvs_get_u8(handle, key.c_str(), &value);

    // Step 3: Close NVS handle regardless of success/failure
    nvs_close(handle);

    // Step 4: Handle result
    if (err == ESP_OK) {
        return static_cast<bool>(value);
    } else {
        // Key not found or read error occurred
        return default_value;
    }
}

#include <string>
#include <cstdint>
#include "nvs.h"
#include "esp_log.h"

// Assume these are declared elsewhere in your class or global scope:
extern nvs_handle_t nvs_handle;
extern bool is_nvs_writable;
extern bool settings_dirty;

static const char* TAG = "Settings";

void SetBool(const std::string& key, bool value) {
    // Step 1: Check if NVS namespace is open for writing
    if (!is_nvs_writable) {
        ESP_LOGW(TAG, "NVS not writable, cannot set key '%s'", key.c_str());
        return;
    }

    // Step 2: Convert boolean to uint8_t
    uint8_t val_uint8 = static_cast<uint8_t>(value ? 1 : 0);

    // Step 3: Store the converted value in NVS under the provided key
    esp_err_t err = nvs_set_u8(nvs_handle, key.c_str(), val_uint8);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write key '%s' to NVS, error=0x%x", key.c_str(), err);
        return;
    }

    // Step 4: Mark settings as dirty after successful write
    settings_dirty = true;

    // Optional: Commit changes immediately (depending on design)
    nvs_commit(nvs_handle);
}

void Settings::EraseKey(const std::string& key) {
    // Step 1: Check if NVS is open for writing
    if (IsReadOnly()) {
        ESP_LOGW("Settings", "Cannot erase key '%s' - NVS is read-only", key.c_str());
        return;
    }

    // Step 2: Attempt to erase the key
    esp_err_t err = nvs_erase_key(nvs_handle_, key.c_str());

    // Step 3: Handle result gracefully
    if (err == ESP_ERR_NVS_NOT_FOUND) {
        // Key does not exist; this is OK, just ignore
        return;
    } else if (err != ESP_OK) {
        ESP_LOGE("Settings", "Failed to erase key '%s': %s", key.c_str(), esp_err_to_name(err));
        return;
    }

    // Step 4: Commit changes
    err = nvs_commit(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE("Settings", "Failed to commit NVS changes after erasing key '%s': %s",
                 key.c_str(), esp_err_to_name(err));
    }
}

void Settings::EraseAll() {
    // Step 1: Check if the NVS namespace is open for writing
    if (isReadOnly()) {
        // Step 2: If read-only, log a warning and exit
        ESP_LOGW("Settings", "NVS namespace is read-only; cannot erase settings.");
        return;
    }

    // Step 3: Erase all settings from the NVS namespace
    esp_err_t err = nvs_erase_all(nvsHandle);
    if (err != ESP_OK) {
        ESP_LOGE("Settings", "Failed to erase NVS settings: %s", esp_err_to_name(err));
        return;
    }

    // Step 4: Commit changes to NVS storage
    err = nvs_commit(nvsHandle);
    if (err != ESP_OK) {
        ESP_LOGE("Settings", "Failed to commit NVS changes: %s", esp_err_to_name(err));
        return;
    }

    ESP_LOGI("Settings", "All settings erased successfully.");
}

