esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Define buffer sizes for two snapshots
    const size_t max_tasks = 32;
    TaskStatus_t pxTaskStatusArray_initial[max_tasks];
    TaskStatus_t pxTaskStatusArray_final[max_tasks];
    uint32_t ulTotalRunTime_initial, ulTotalRunTime_final;

    // Step 1: Capture initial task runtime statistics
    UBaseType_t uxArraySize_initial = uxTaskGetSystemState(pxTaskStatusArray_initial, max_tasks, &ulTotalRunTime_initial);
    if (uxArraySize_initial == 0) {
        printf("Failed to retrieve initial task states.\n");
        return ESP_FAIL;
    }

    // Step 2: Delay for the specified interval
    vTaskDelay(xTicksToWait);

    // Step 3: Capture final task runtime statistics
    UBaseType_t uxArraySize_final = uxTaskGetSystemState(pxTaskStatusArray_final, max_tasks, &ulTotalRunTime_final);
    if (uxArraySize_final == 0) {
        printf("Failed to retrieve final task states.\n");
        return ESP_FAIL;
    }

    // Compute total elapsed time across all cores (approximated)
    uint32_t ulTotalElapsedTime = ulTotalRunTime_final - ulTotalRunTime_initial;

    if (ulTotalElapsedTime == 0) {
        printf("No elapsed time recorded; cannot calculate CPU usage.\n");
        return ESP_OK;
    }

    // Step 4 & 5: Match tasks between snapshots and calculate CPU usage
    printf("\nTask CPU Usage Over %lu Ticks:\n", xTicksToWait);
    printf("------------------------------------------------------------\n");
    printf("| Task Name       | CPU %%     | Status         |\n");
    printf("------------------------------------------------------------\n");

    bool task_found_in_both;
    bool task_deleted_flag = false;
    bool task_created_flag = false;

    // Loop through initial tasks
    for (UBaseType_t i = 0; i < uxArraySize_initial; i++) {
        TaskHandle_t hInitialTask = pxTaskStatusArray_initial[i].xHandle;
        char* pcInitialName = pxTaskStatusArray_initial[i].pcTaskName;
        uint32_t ulInitialRuntime = pxTaskStatusArray_initial[i].ulRunTimeCounter;

        task_found_in_both = false;

        // Search for matching task in final array
        for (UBaseType_t j = 0; j < uxArraySize_final; j++) {
            if (pxTaskStatusArray_final[j].xHandle == hInitialTask) {
                uint32_t ulFinalRuntime = pxTaskStatusArray_final[j].ulRunTimeCounter;
                uint32_t ulRunTimeDiff = ulFinalRuntime - ulInitialRuntime;

                float fCpuPercent = ((float)ulRunTimeDiff / ulTotalElapsedTime) * 100.0f;

                printf("| %-15s | %7.2f%% | Active           |\n", pcInitialName, fCpuPercent);
                task_found_in_both = true;
                break;
            }
        }

        if (!task_found_in_both) {
            printf("| %-15s |      N/A  | Deleted          |\n", pcInitialName);
            task_deleted_flag = true;
        }
    }

    // Check for new tasks not present in initial snapshot
    for (UBaseType_t j = 0; j < uxArraySize_final; j++) {
        TaskHandle_t hFinalTask = pxTaskStatusArray_final[j].xHandle;
        bool found = false;

        for (UBaseType_t i = 0; i < uxArraySize_initial; i++) {
            if (pxTaskStatusArray_initial[i].xHandle == hFinalTask) {
                found = true;
                break;
            }
        }

        if (!found) {
            char* pcFinalName = pxTaskStatusArray_final[j].pcTaskName;
            printf("| %-15s |      N/A  | Created          |\n", pcFinalName);
            task_created_flag = true;
        }
    }

    // Report summary of changes
    if (!task_deleted_flag && !task_created_flag) {
        printf("------------------------------------------------------------\n");
        printf("No tasks were created or deleted during this period.\n");
    } else {
        if (task_deleted_flag)
            printf("Some tasks were deleted.\n");
        if (task_created_flag)
            printf("Some tasks were created.\n");
    }

    printf("------------------------------------------------------------\n\n");

    return ESP_OK;
}

