    constexpr size_t TASK_LIST_BUFFER_SIZE = 2048;

    // Allocate memory for task list buffer
    char* task_list_buffer = static_cast<char*>(malloc(TASK_LIST_BUFFER_SIZE));
    if (task_list_buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for task list buffer");
        return;
