bool AudioCodec::InputData(std::vector<int16_t>& data) {
    // Step 1: Check if input is enabled
    if (!input_enabled_) {
        return false;
    }

    // Step 2: Prepare buffer size according to expected frame number and channel count
    size_t num_samples = AUDIO_CODEC_DMA_FRAME_NUM * input_channels_;
    data.resize(num_samples);

    // Step 3: Use the pure virtual Read function to get actual data
    int samples_read = Read(data.data(), static_cast<int>(num_samples));

    // Step 4: Handle end-of-stream or error conditions
    if (samples_read <= 0) {
        data.clear();
        return false;
    }

    // Optional: resize vector to match exactly how many samples were read (in case less than requested)
    data.resize(samples_read);

    // Step 5: Return true indicating successful read
    return true;
}

