void AudioCodec::Start() {
    // Initialize I2S transmit and receive handles with configured parameters
    if (tx_handle_ == nullptr && output_channels_ > 0) {
        i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_AUTO, I2S_ROLE_MASTER);
        tx_chan_cfg.dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM;
        tx_chan_cfg.dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM;
        tx_chan_cfg.auto_clear = true;

        esp_err_t ret = i2s_new_channel(&tx_chan_cfg, &tx_handle_, nullptr);
        if (ret != ESP_OK) {
            ESP_LOGE("AUDIO_CODEC", "Failed to create I2S TX channel: %s", esp_err_to_name(ret));
            return;
        }

        i2s_std_config_t tx_std_cfg = {
            .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(output_sample_rate_),
            .slot_cfg = I2S_STD_MSB_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_MONO),
            .gpio_cfg = {
                .mclk = I2S_GPIO_UNUSED,
                .bclk = I2S_GPIO_UNUSED,
                .ws = I2S_GPIO_UNUSED,
                .dout = I2S_GPIO_UNUSED,
                .din = I2S_GPIO_UNUSED,
                .invert_flags = {
                    .mclk_inv = false,
                    .bclk_inv = false,
                    .ws_inv = false,
                },
            },
        };

        ret = i2s_channel_init_std_mode(tx_handle_, &tx_std_cfg);
        if (ret != ESP_OK) {
            ESP_LOGE("AUDIO_CODEC", "Failed to initialize I2S TX standard mode: %s", esp_err_to_name(ret));
            return;
        }
    }

    if (rx_handle_ == nullptr && input_channels_ > 0) {
        i2s_chan_config_t rx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_AUTO, I2S_ROLE_MASTER);
        rx_chan_cfg.dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM;
        rx_chan_cfg.dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM;

        esp_err_t ret = i2s_new_channel(&rx_chan_cfg, nullptr, &rx_handle_);
        if (ret != ESP_OK) {
            ESP_LOGE("AUDIO_CODEC", "Failed to create I2S RX channel: %s", esp_err_to_name(ret));
            return;
        }

        i2s_std_config_t rx_std_cfg = {
            .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(input_sample_rate_),
            .slot_cfg = I2S_STD_MSB_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_MONO),
            .gpio_cfg = {
                .mclk = I2S_GPIO_UNUSED,
                .bclk = I2S_GPIO_UNUSED,
                .ws = I2S_GPIO_UNUSED,
                .dout = I2S_GPIO_UNUSED,
                .din = I2S_GPIO_UNUSED,
                .invert_flags = {
                    .mclk_inv = false,
                    .bclk_inv = false,
                    .ws_inv = false,
                },
            },
        };

        ret = i2s_channel_init_std_mode(rx_handle_, &rx_std_cfg);
        if (ret != ESP_OK) {
            ESP_LOGE("AUDIO_CODEC", "Failed to initialize I2S RX standard mode: %s", esp_err_to_name(ret));
            return;
        }
    }

    // Apply saved or default volume settings to input and output channels
    if (output_enabled_) {
        SetOutputVolume(output_volume_);
    }

    if (input_enabled_) {
        SetInputGain(input_gain_);
    }

    // Enable and activate the audio input and output paths
    if (tx_handle_ != nullptr) {
        esp_err_t ret = i2s_channel_enable(tx_handle_);
        if (ret != ESP_OK) {
            ESP_LOGE("AUDIO_CODEC", "Failed to enable I2S TX channel: %s", esp_err_to_name(ret));
        }
    }

    if (rx_handle_ != nullptr) {
        esp_err_t ret = i2s_channel_enable(rx_handle_);
        if (ret != ESP_OK) {
            ESP_LOGE("AUDIO_CODEC", "Failed to enable I2S RX channel: %s", esp_err_to_name(ret));
        }
    }

    // Enable input/output based on configuration
    if (output_channels_ > 0) {
        EnableOutput(true);
    }

    if (input_channels_ > 0) {
        EnableInput(true);
    }
}

