void AudioCodec::SetInputGain(float gain) {
    // Step 1: Validate and clamp the input gain to [0.0, 1.0]
    if (gain < 0.0f) {
        gain = 0.0f;
    } else if (gain > 1.0f) {
        gain = 1.0f;
    }

    // Step 2: Convert gain (0.0 - 1.0) to register value (example: 0 - 31)
    uint8_t reg_value = static_cast<uint8_t>(gain * 31);

