    // These register addresses may vary; these are common ones for ES8388
    constexpr uint8_t kLeftInputPGAGainReg = 0x21;
    constexpr uint8_t kRightInputPGAGainReg = 0x22;

    // Assuming WriteRegister is implemented in derived class or accessible here
    WriteRegister(kLeftInputPGAGainReg, reg_value);
    WriteRegister(kRightInputPGAGainReg, reg_value);

    // Step 4: Update internal state
    input_gain_ = gain;

    // Step 5: Log the updated gain for debugging
    ESP_LOGD("AudioCodec", "Input gain set to %.2f (reg value: %d)", gain, reg_value);
}

