void AudioCodec::EnableOutput(bool enable) {
    // Step 1: Check if the requested output state differs from the current state
    if (output_enabled_ == enable) {
        return; // No change required
    }

    // Step 2: Update the internal output enable flag
    output_enabled_ = enable;

    // Step 3: Invoke low-level hardware control to enable or disable audio output
    if (enable) {
        if (tx_handle_) {
            i2s_channel_enable(tx_handle_);
        }
        // Additional codec-specific enable could go here (e.g., power up DAC)
    } else {
        if (tx_handle_) {
            i2s_channel_disable(tx_handle_);
        }
        // Additional codec-specific disable could go here (e.g., power down DAC)
    }

    // Step 4: Log the output state transition for debugging purposes
    if (enable) {
        ESP_LOGI("AudioCodec", "Audio output enabled");
    } else {
        ESP_LOGI("AudioCodec", "Audio output disabled");
    }
}

#include "driver/i2c.h"
#include "driver/i2s_std.h"
#include "driver/gpio.h"
#include "es8388_reg.h" // Assuming contains definitions for register addresses

// Assume global/static instance variables declared elsewhere
extern i2s_chan_handle_t rx_i2s_chan;
extern i2s_chan_handle_t tx_i2s_chan;

void Es8388AudioCodec::Es8388AudioCodec(
    void *ctx,
    i2c_port_t port,
    int input_sample_rate,
    int output_sample_rate,
    gpio_num_t sck_pin,
    gpio_num_t ws_pin,
    gpio_num_t data_in_pin,
    gpio_num_t data_out_pin,
    gpio_num_t pa_enable_pin,
    gpio_num_t ref_input_pin,
    uint8_t i2c_address,
    bool use_aec_ref
) {
    // Step 1: Initialize I2C Master for Communication with ES8388
    const i2c_config_t conf = {
        .mode = I2C_MODE_MASTER,
        .sda_io_num = static_cast<gpio_num_t>(21), // Typical SDA pin; adjust accordingly
        .scl_io_num = static_cast<gpio_num_t>(22), // Typical SCL pin
        .sda_pullup_en = GPIO_PULLUP_ENABLE,
        .scl_pullup_en = GPIO_PULLUP_ENABLE,
        .master = {
            .clk_speed = 100000
        },
        .clk_flags = 0
    };
    i2c_param_config(port, &conf);
    i2c_driver_install(port, conf.mode, 0, 0, 0);

    // Step 2: Initialize I2S for Input and Output
    i2s_std_config_t std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(output_sample_rate),
        .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = I2S_GPIO_UNUSED,
            .bclk = sck_pin,
            .ws = ws_pin,
            .dout = data_out_pin,
            .din = data_in_pin,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false
            }
        }
    };

    // Install TX I2S Channel
    i2s_new_channel(&std_cfg, &tx_i2s_chan, nullptr);

    // Install RX I2S Channel
    i2s_new_channel(&std_cfg, nullptr, &rx_i2s_chan);

    // Step 3: Setup GPIO Controls
    gpio_set_direction(pa_enable_pin, GPIO_MODE_OUTPUT);
    gpio_set_level(pa_enable_pin, 1); // Turn on PA

    if (use_aec_ref && ref_input_pin != GPIO_NUM_NC) {
        gpio_set_direction(ref_input_pin, GPIO_MODE_INPUT);
    }

    // Step 4: Initialize ES8388 Registers
    es8388_init_reg(); // Basic reset/init sequence

    // Set sample rates
    es8388_write_reg(ES8388_ADCCONTROL4, ((input_sample_rate == 48000) ? 0x08 : 0x00));
    es8388_write_reg(ES8388_DACCONTROL2, ((output_sample_rate == 48000) ? 0x08 : 0x00));

    // Configure ADC and DAC paths
    es8388_write_reg(ES8388_ADCCONTROL1, 0xBF); // MIC Left/Right PGA gain + Line-in
    es8388_write_reg(ES8388_ADCCONTROL2, 0x00); // LINSEL & RINSEL, differential input
    es8388_write_reg(ES8388_DACCONTROL1, 0x18); // LOUT1 & ROUT1 enable, default volume
    es8388_write_reg(ES8388_DACCONTROL24, 0x04); // DAC soft ramp rate

    // Step 5: Enable Full Duplex
    es8388_write_reg(ES8388_CHIPPOWER, 0x00); // Power up all modules except internal reference

    // Start I2S channels
    i2s_channel_enable(tx_i2s_chan);
    i2s_channel_enable(rx_i2s_chan);
}

~Es8388AudioCodec() {
  // Step 1: Deinitialize I2S input/output devices
  if (i2s_input_) {
    i2s_input_->Deinitialize();
    delete i2s_input_;
    i2s_input_ = nullptr;
  }

  if (i2s_output_) {
    i2s_output_->Deinitialize();
    delete i2s_output_;
    i2s_output_ = nullptr;
  }

  // Step 2: Close and delete associated control interfaces (I2C, GPIO)
  if (i2c_interface_) {
    i2c_interface_->Close();
    delete i2c_interface_;
    i2c_interface_ = nullptr;
  }

  if (gpio_reset_pin_) {
    gpio_reset_pin_->Unconfigure();
    delete gpio_reset_pin_;
    gpio_reset_pin_ = nullptr;
  }

  // Step 3: Release data interface resources and buffers
  if (dma_buffer_) {
    // Assuming there's a memory manager or allocator involved
    free(dma_buffer_);
    dma_buffer_ = nullptr;
    buffer_size_ = 0;
  }

  // Step 4: Unregister and free hardware abstraction layer components
  if (hal_component_) {
    hal_component_->Unregister();
    delete hal_component_;
    hal_component_ = nullptr;
  }

  // Step 5: Perform final power-down or reset sequence on ES8388
  if (initialized_) {
    // Send shutdown command via I2C
    uint8_t shutdown_cmd = 0x00; // Placeholder value - actual depends on datasheet
    i2c_interface_->WriteRegister(ES8388_REG_CHIP_CONTROL, shutdown_cmd);

    // Optionally toggle reset pin
    if (gpio_reset_pin_) {
      gpio_reset_pin_->SetLow();  // Assert reset
      // Delay may be needed depending on hardware timing requirements
    }
  }

  // Step 6: Clear internal state and mark destructor completion
  initialized_ = false;
}

#include "driver/i2s_std.h"
#include "es8388_audio_codec.h"

esp_err_t CreateDuplexChannels(gpio_num_t bck, gpio_num_t ws, gpio_num_t dout, gpio_num_t din, gpio_num_t mck) {
    i2s_chan_handle_t tx_handle = NULL;
    i2s_chan_handle_t rx_handle = NULL;

    // Step 1: Configure I2S channel configurations
    i2s_std_config_t std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(24000), // 24kHz sample rate
        .slot_cfg = I2S_STD_PHILIP_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = mck,
            .bclk = bck,
            .ws = ws,
            .dout = dout,
            .din = din,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false,
            },
        },
    };

    // Step 2: Initialize I2S controller in duplex mode
    i2s_new_channel(&std_cfg, &tx_handle, &rx_handle);

    if (tx_handle == NULL || rx_handle == NULL) {
        return ESP_FAIL;
    }

    // Step 3: Enable both TX and RX channels
    i2s_channel_enable(tx_handle);
    i2s_channel_enable(rx_handle);

    return ESP_OK;
}

