void ES8388AudioCodec::EnableInput(bool enable) {
    // Step 1: Validate current state vs desired state
    if (input_enabled_ == enable) {
        return; // No change required
    }

    if (enable) {
        // Step 2: Configure I2S input settings
        ConfigureI2sRxChannel();

        // Step 3: Apply input gain setting
        SetInputGain(input_gain_);

        // Step 4: Start the input stream
        if (rx_handle_) {
            i2s_channel_enable(rx_handle_);
        }

        // Update internal flag
        input_enabled_ = true;
    } else {
        // Step 4: Close the input stream
        if (rx_handle_) {
            i2s_channel_disable(rx_handle_);
        }

        // Optionally power down ADC or related circuits here via I2C

        // Update internal flag
        input_enabled_ = false;
    }
}

