void ES8388AudioCodec::EnableOutput(bool enable) {
    // Avoid reconfiguration if already in desired state
    if (output_enabled_ == enable) {
        return;
    }

    if (enable) {
        // Step 1: Initialize/configure I2S interface for output
        if (tx_handle_ == nullptr) {
            i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_AUTO, I2S_ROLE_MASTER);
            ESP_ERROR_CHECK(i2s_new_channel(&tx_chan_cfg, &tx_handle_, nullptr));

            i2s_std_config_t std_cfg = {
                .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(output_sample_rate_),
                .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_MONO),
                .gpio_cfg = {
                    .mclk = I2S_GPIO_UNUSED,
                    .bclk = (gpio_num_t)GET_PIN(I2S_SCLK),
                    .ws = (gpio_num_t)GET_PIN(I2S_LCLK),
                    .dout = (gpio_num_t)GET_PIN(I2S_DOUT),
                    .din = I2S_GPIO_UNUSED,
                    .invert_flags = {
                        .mclk_inv = false,
                        .bclk_inv = false,
                        .ws_inv = false,
                    },
                },
            };
            ESP_ERROR_CHECK(i2s_channel_init_std_mode(tx_handle_, &std_cfg));
        }
        ESP_ERROR_CHECK(i2s_channel_enable(tx_handle_));

        // Step 2: Configure ES8388 registers for output path
        WriteRegister(0x00, 0x00); // Reset all registers (optional)

        // Configure DAC and Analog Output Path
        WriteRegister(0x02, 0xF3); // Power Management 1: Enable DACL, DACR, and LOUT/RLOUT
        WriteRegister(0x03, 0xFF); // Power Management 2: Disable ADC inputs
        WriteRegister(0x04, 0x80); // Power Management 3: Enable VMID

        WriteRegister(0x09, 0x02); // Clock Manager: MCLK divided by 2
        WriteRegister(0x0A, 0x02); // Sample Rate Setting: Use default setting matching I2S clock

        WriteRegister(0x0D, 0x02); // DAC Control 0: Digital DAC volume soft ramping enabled
        WriteRegister(0x10, 0x00); // DAC Volume Control: Set initial volume low before unmute
        WriteRegister(0x11, 0x00);

        WriteRegister(0x12, 0x22); // DAC Control 1: Unmute both DAC channels
        WriteRegister(0x14, 0x1E); // Analog Output Control 1: LOUT/RLOUT unmuted, gain +0dB
        WriteRegister(0x15, 0x02); // Analog Output Control 2: Enable LOUT/RLOUT

        // Apply user-defined volume level after unmuting
        SetOutputVolume(output_volume_);

        // Step 3: Enable external power amplifier GPIO if applicable
        SetAmplifierPin(true);
    } else {
        // Step 1: Disable power amplifier GPIO
        SetAmplifierPin(false);

        // Step 2: Mute DAC outputs and shut down analog paths
        WriteRegister(0x12, 0x00); // DAC Control 1: Mute both DAC channels
        WriteRegister(0x02, 0xFF); // Power Management 1: Shut down DAC and output drivers

        // Step 3: Stop and release I2S TX channel
        if (tx_handle_) {
            i2s_channel_disable(tx_handle_);
            i2s_del_channel(tx_handle_);
            tx_handle_ = nullptr;
        }
    }

    // Update internal state
    output_enabled_ = enable;
}

int Es8388AudioCodec::Read(int16_t *buffer, int num_samples) {
    // Step 1: Check if input is enabled
    if (!input_enabled_) {
        return 0;
    }

    // Step 2: Prepare buffer and calculate size in bytes
    size_t bytes_to_read = num_samples * sizeof(int16_t);

    // Step 3: Call ESP-IDF codec device API to read PCM samples
    ssize_t bytes_read = codec_dev_read(codec_device_handle_, buffer, bytes_to_read);

    // Step 4: Validate number of bytes read and convert back to sample count
    if (bytes_read < 0) {
        // Error occurred during read
        return 0;
    }

    int samples_read = static_cast<int>(bytes_read / sizeof(int16_t));
    return samples_read;
}

#include "es8388_audio_codec.h"

int ES8388AudioCodec::Write(const int16_t* data, int sample_count) {
    // Step 1: Validate input parameters
    if (!data || sample_count < 0) {
        return 0;
    }

    // Step 2: Check if output is enabled
    if (!IsOutputEnabled()) {
        return 0;
    }

    // Step 3: Check device validity
    if (!IsValid()) {
        return 0;
    }

    // Step 4: Convert sample count to byte size
    size_t byte_size = static_cast<size_t>(sample_count) * sizeof(int16_t);

    // Step 5: Transmit data via I2S
    bool success = TransmitI2S(reinterpret_cast<const uint8_t*>(data), byte_size);

    // Step 6: Return number of samples written based on transmission result
    return success ? sample_count : 0;
}

