class AudioDebugger {
private:
    int udp_socket_;
    struct sockaddr_in server_addr_;
    bool initialized_;

public:
    // Constructor / Callable Object Functionality
    AudioDebugger() : udp_socket_(-1), initialized_(false) {
        std::string server_ip;
        int server_port;

        // Step 1: Parse server IP and port from configuration
        if (!Board::getDebugServerAddress(server_ip, server_port)) {
            Logging::LOG_ERROR("Failed to retrieve debug server address from config.");
            return;
        }

        // Step 2: Initialize UDP socket
        udp_socket_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
        if (udp_socket_ < 0) {
            Logging::LOG_ERROR("Failed to create UDP socket.");
            return;
        }

        // Setup server address structure
        memset(&server_addr_, 0, sizeof(server_addr_));
        server_addr_.sin_family = AF_INET;
        server_addr_.sin_port = htons(server_port);

        if (inet_pton(AF_INET, server_ip.c_str(), &server_addr_.sin_addr) <= 0) {
            Logging::LOG_ERROR("Invalid server IP address.");
            close(udp_socket_);
            udp_socket_ = -1;
            return;
        }

        // Optional: Attempt connection (for connected UDP sockets)
        // Not strictly necessary for sending unconnected packets

        initialized_ = true;
        Logging::LOG_INFO("AudioDebugger successfully initialized.");
    }

    ~AudioDebugger() {
        if (udp_socket_ >= 0) {
            close(udp_socket_);
        }
    }

    // Example usage function for transmitting data
    bool sendData(const void* data, size_t length) {
        if (!initialized_) return false;

        ssize_t sent = sendto(udp_socket_, data, length, 0,
                              reinterpret_cast<struct sockaddr*>(&server_addr_), sizeof(server_addr_));
        return sent == static_cast<ssize_t>(length);
    }
};

AudioDebugger::~AudioDebugger() {
    // Step 1: Check if the audio debugger feature is enabled
    if (!is_enabled_) {
        return;
    }

    // Step 2: Log the cleanup action for debugging purposes
    LOG(INFO) << "Cleaning up AudioDebugger resources.";

    // Step 3: Close and deallocate the UDP socket resource
    if (udp_socket_.IsValid()) {
        udp_socket_.Close();
        LOG(INFO) << "UDP socket closed successfully.";
    } else {
        LOG(WARNING) << "UDP socket was not valid during cleanup.";
    }

    // Step 4: Ensure all network resources are properly released
    // Reset internal state if necessary
    is_enabled_ = false;
}

