#define DEBUG_SERVER_IP "127.0.0.1"
#define DEBUG_SERVER_PORT 9999

#endif // ENABLE_AUDIO_DEBUG

void AudioDebugger::Feed(const std::vector<int16_t>& samples) {
#ifdef ENABLE_AUDIO_DEBUG

    if (samples.empty()) {
        // Nothing to send
        return;
    }

    // Step 1: Convert int16_t samples to byte stream
    size_t num_bytes = samples.size() * sizeof(int16_t);
    std::vector<uint8_t> byte_buffer(num_bytes);
    std::memcpy(byte_buffer.data(), samples.data(), num_bytes);

    // Step 2: Create UDP socket
    int sock = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (sock < 0) {
        std::cerr << "[AudioDebugger] Failed to create UDP socket." << std::endl;
        return;
    }

    struct sockaddr_in server_addr {};
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(DEBUG_SERVER_PORT);
    inet_pton(AF_INET, DEBUG_SERVER_IP, &server_addr.sin_addr);

    // Step 3: Send data
    ssize_t bytes_sent = sendto(sock, byte_buffer.data(), num_bytes, 0,
                                reinterpret_cast<struct sockaddr*>(&server_addr),
                                sizeof(server_addr));

    // Step 4: Log result
    if (bytes_sent < 0) {
        std::cerr << "[AudioDebugger] Error sending audio data over UDP." << std::endl;
    } else if (static_cast<size_t>(bytes_sent) != num_bytes) {
        std::cerr << "[AudioDebugger] Incomplete packet sent. Sent "
                  << bytes_sent << "/" << num_bytes << " bytes." << std::endl;
    } else {
        std::cout << "[AudioDebugger] Successfully sent "
                  << bytes_sent << " bytes of audio data." << std::endl;
    }

    close(sock);

#else
    // Audio debugging not enabled - do nothing
#endif
}

