void AfeWakeWord::Stop() {
    // Step 1: Check if AFE is initialized
    if (afe_data_ == nullptr || afe_iface_ == nullptr) {
        ESP_LOGW(TAG, "AFE not initialized. Cannot stop.");
        return;
    }

    // Step 2: Clear the detection running event flag
    if (event_group_ != nullptr) {
        xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);
    }

    // Step 3: Reset the audio front-end buffer
    if (afe_iface_->reset_buffer && afe_data_) {
        afe_iface_->reset_buffer(afe_data_);
    }

    // Optional: Log confirmation
    ESP_LOGI(TAG, "Wake word detection stopped.");
}

void AfeWakeWord::Feed(const std::vector<int16_t>& pcm_data) {
    // Step 1: Validate the internal AFE data buffer/context
    if (!afe_handle_) {
        // AFE not initialized or invalid; cannot proceed
        return;
    }

    // Step 2: Feed PCM samples into the AFE processing pipeline
    if (!pcm_data.empty()) {
        // Assuming there's a function to feed data into AFE engine
        afe_result_t result = afe_process_samples(afe_handle_, pcm_data.data(), pcm_data.size());

        // Step 3: Handle wake word detection results from AFE output
        if (result == AFE_RESULT_WAKEWORD_DETECTED) {
            // Step 4: Update internal state and notify audio service of detection
            OnWakeWordDetected();
        } else if (result == AFE_RESULT_ERROR) {
            // Optional error handling
            HandleError(AFE_ERROR_PROCESSING_FAILED);
        }
    }
}

