void AfeWakeWord::AudioDetectionTask() {
    const TickType_t xMaxBlockTime = pdMS_TO_TICKS(100); // Max wait time for event group bits

    while (true) {
        // Wait until started or exit if stopping
        EventBits_t uxBits = xEventGroupWaitBits(event_group_,
                                                 /* uxBitsToWaitFor= */ 0x01, // Assuming bit 0 means "start"
                                                 /* xClearOnExit= */ pdFALSE,
                                                 /* xWaitForAllBits= */ pdTRUE,
                                                 xMaxBlockTime);

        if ((uxBits & 0x01) == 0) {
            continue; // Not yet started
        }

        // Ensure AFE is properly initialized
        if (!afe_iface_ || !afe_data_) {
            ESP_LOGE(TAG, "AFE not initialized");
            vTaskDelay(pdMS_TO_TICKS(100));
            continue;
        }

        // Get expected feed size per chunk
        size_t feed_size = afe_iface_->get_feed_chunksize(afe_data_);
        std::vector<int16_t> audio_buffer(feed_size);

        while ((uxBits & 0x01) != 0) { // While still active
            // Read audio data from codec/I2S driver
            if (codec_ && codec_->Read(audio_buffer.data(), feed_size)) {
                // Feed data into AFE for processing
                afe_iface_->feed(afe_data_, (int16_t *)audio_buffer.data());

                // Fetch detection result
                esp_afe_sr_result_t result = afe_iface_->fetch_result(afe_data_);

                if (result.wakeup_state == WAKE_UP) {
                    // Wake word detected!
                    std::string detected_keyword = result.wakenet_mode ? result.wakenet_mode : "unknown";

                    // Save last detected wake word
                    last_detected_wake_word_ = detected_keyword;

                    // Store buffered audio (pre-trigger + post-trigger)
                    StoreWakeWordData(audio_buffer.data(), feed_size);

                    // Stop feeding temporarily and notify upper layer
                    if (wake_word_detected_callback_) {
                        wake_word_detected_callback_(detected_keyword);
                    }

                    // Give some grace period before restarting
                    vTaskDelay(pdMS_TO_TICKS(500));

                    // Clear buffers and reset state
                    // Note: This depends on actual AFE API behavior – might require re-init or just flush
                    afe_iface_->reset(afe_data_);

                    break; // Exit inner loop to check start condition again
                }
            } else {
                vTaskDelay(pdMS_TO_TICKS(10)); // Brief delay if no data available
            }

            // Re-check event group for stop signal
            uxBits = xEventGroupGetBits(event_group_);
        }
    }
}

