#include "FreeRTOS.h"
#include "semphr.h" // For semaphore/mutex support

class AfeWakeWord {
private:
    static const size_t kSampleRate = 16000;
    static const size_t kBufferDurationSeconds = 2;
    static const size_t kMaxBufferSize = kSampleRate * kBufferDurationSeconds;

    int16_t buffer_[kMaxBufferSize];
    volatile size_t write_index_ = 0;
    SemaphoreHandle_t buffer_mutex_;

public:
    AfeWakeWord() {
        buffer_mutex_ = xSemaphoreCreateMutex();
        if (buffer_mutex_ == NULL) {
            // Handle error: failed to create mutex
        }
    }

    ~AfeWakeWord() {
        if (buffer_mutex_ != NULL) {
            vSemaphoreDelete(buffer_mutex_);
        }
    }

    void StoreWakeWordData(const int16_t* data, size_t length) {
        if (data == nullptr || length == 0) {
            return;
        }

        // Acquire lock to ensure thread safety
        if (xSemaphoreTake(buffer_mutex_, portMAX_DELAY) != pdTRUE) {
            return; // Failed to acquire lock
        }

        for (size_t i = 0; i < length; ++i) {
            buffer_[write_index_] = data[i];
            write_index_ = (write_index_ + 1) % kMaxBufferSize;
        }

        // Release lock after updating buffer
        xSemaphoreGive(buffer_mutex_);
    }
};

