// Constants for Opus encoder setup
#define OPUS_SAMPLE_RATE       16000
#define OPUS_CHANNELS          1
#define OPUS_FRAME_SIZE_MS     20
#define OPUS_FRAME_SIZE_SAMPLES (OPUS_SAMPLE_RATE * OPUS_FRAME_SIZE_MS / 1000)
#define OPUS_MAX_PACKET_SIZE   4000

static void WakeWordEncodeTask(void* pvParameters);

void AfeWakeWord::EncodeWakeWordData() {
    // Avoid duplicate task creation
    if (wake_word_encode_task_ != nullptr) {
        return;
    }

    const size_t stack_size_bytes = 4096;
    const uint32_t caps = MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT;

    // Allocate stack in SPIRAM if available
    wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(stack_size_bytes, caps);
    if (!wake_word_encode_task_stack_) {
        // Fallback to internal memory
        wake_word_encode_task_stack_ = (StackType_t*)malloc(stack_size_bytes);
        if (!wake_word_encode_task_stack_) {
            // Handle error: unable to allocate memory
            return;
        }
    }

    // Allocate task buffer in internal memory
    wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    if (!wake_word_encode_task_buffer_) {
        free(wake_word_encode_task_stack_);
        return;
    }

    // Create the task using statically allocated memory
    wake_word_encode_task_ = xTaskCreateStatic(
        WakeWordEncodeTask,
        "WakeWordEncode",
        stack_size_bytes / sizeof(StackType_t),
        this,
        tskIDLE_PRIORITY + 5,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == NULL) {
        // Cleanup on failure
        free(wake_word_encode_task_stack_);
        free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
    }
}

// Static task function executed by the encoder task
static void WakeWordEncodeTask(void* pvParameters) {
    AfeWakeWord* instance = static_cast<AfeWakeWord*>(pvParameters);

    int opus_error = 0;
    OpusEncoder* encoder = opus_encoder_create(OPUS_SAMPLE_RATE, OPUS_CHANNELS, OPUS_APPLICATION_VOIP, &opus_error);
    if (opus_error != OPUS_OK || !encoder) {
        // Failed to create encoder
        vTaskDelete(NULL);
        return;
    }

    opus_encoder_ctl(encoder, OPUS_SET_SIGNAL(OPUS_SIGNAL_VOICE));
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1)); // Low complexity for speed
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));

    std::vector<uint8_t> encoded_packet(OPUS_MAX_PACKET_SIZE);

    while (true) {
        std::unique_lock<std::mutex> lock(instance->wake_word_mutex_);

        if (instance->wake_word_pcm_.empty()) {
            lock.unlock();
            vTaskDelay(pdMS_TO_TICKS(10)); // Wait briefly before checking again
            continue;
        }

        auto pcm_frame = std::move(instance->wake_word_pcm_.front());
        instance->wake_word_pcm_.pop_front();
        lock.unlock();

        if (pcm_frame.size() != OPUS_FRAME_SIZE_SAMPLES) {
            continue; // Skip malformed frames
        }

        int encoded_bytes = opus_encode(encoder, pcm_frame.data(), OPUS_FRAME_SIZE_SAMPLES,
                                        encoded_packet.data(), encoded_packet.size());

        if (encoded_bytes > 0) {
            std::lock_guard<std::mutex> output_lock(instance->wake_word_mutex_);
            instance->wake_word_opus_.emplace_back(encoded_packet.begin(),
                                                   encoded_packet.begin() + encoded_bytes);
            instance->wake_word_cv_.notify_one();
        }
    }

    opus_encoder_destroy(encoder);
    vTaskDelete(NULL);
}

