bool CustomWakeWord::ParseWakenetModelConfig() {
    const char* config_path = "/path/to/index.json"; // Adjust according to actual deployment path
    std::ifstream file(config_path);

    if (!file.is_open()) {
        ESP_LOGE(TAG, "Failed to open config file: %s", config_path);
        return false;
    }

    std::stringstream buffer;
    buffer << file.rdbuf();
    std::string json_str = buffer.str();

    cJSON* root = cJSON_Parse(json_str.c_str());
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON from config file");
        return false;
    }

    // Parse language
    cJSON* lang_item = cJSON_GetObjectItemCaseSensitive(root, "language");
    if (cJSON_IsString(lang_item)) {
        language_ = std::string(lang_item->valuestring);
        ESP_LOGI(TAG, "Parsed Language: %s", language_.c_str());
    } else {
        ESP_LOGW(TAG, "Language not found or invalid type in config");
    }

    // Parse duration
    cJSON* duration_item = cJSON_GetObjectItemCaseSensitive(root, "duration");
    if (cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Parsed Duration: %d ms", duration_);
    } else {
        ESP_LOGW(TAG, "Duration not found or invalid type in config");
    }

    // Parse threshold
    cJSON* threshold_item = cJSON_GetObjectItemCaseSensitive(root, "threshold");
    if (cJSON_IsNumber(threshold_item)) {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
        ESP_LOGI(TAG, "Parsed Threshold: %.2f", threshold_);
    } else {
        ESP_LOGW(TAG, "Threshold not found or invalid type in config");
    }

    // Parse commands
    cJSON* commands_array = cJSON_GetObjectItemCaseSensitive(root, "commands");
    if (cJSON_IsArray(commands_array)) {
        int num_commands = cJSON_GetArraySize(commands_array);
        for (int i = 0; i < num_commands; ++i) {
            cJSON* cmd_obj = cJSON_GetArrayItem(commands_array, i);
            if (cmd_obj) {
                cJSON* id_item = cJSON_GetObjectItemCaseSensitive(cmd_obj, "id");
                cJSON* phrase_item = cJSON_GetObjectItemCaseSensitive(cmd_obj, "phrase");

                if (cJSON_IsString(id_item) && cJSON_IsString(phrase_item)) {
                    std::string id = id_item->valuestring;
                    std::string phrase = phrase_item->valuestring;

                    commands_[id] = phrase;
                    ESP_LOGI(TAG, "Command [%s]: '%s'", id.c_str(), phrase.c_str());
                } else {
                    ESP_LOGW(TAG, "Invalid command entry at index %d", i);
                }
            }
        }
    } else {
        ESP_LOGW(TAG, "Commands section missing or invalid");
    }

    cJSON_Delete(root);
    return true;
}

