        // Step 3: Register custom voice commands based on language and threshold
        for (int j = 0; j < model_entry.command_count; ++j) {
            const auto& cmd = model_entry.commands[j];
            VoiceCommandRegistry::Register(
                cmd.text,
                cmd.language,
                cmd.threshold,
                model_handle
            );
        }
    }

    // Step 4: Verify successful initialization of all components
    if (!AFEFramework::IsWakeWordDetectionReady()) {
        return false;
    }

    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t>& audio_data) {
    // Early exit if already triggered and waiting for reactivation
    if (!is_active_) {
        return;
    }

    // Step 1: Extract left channel if necessary
    std::vector<int16_t> mono_audio;
    const int16_t* input_data = audio_data.data();
    size_t input_size = audio_data.size();

    if (is_stereo_) {
        // Assuming interleaved stereo: L R L R ...
        mono_audio.reserve(input_size / 2);
        for (size_t i = 0; i < input_size; i += 2) {
            mono_audio.push_back(audio_data[i]);  // Take left channel
        }
        input_data = mono_audio.data();
        input_size = mono_audio.size();
    }

    // Step 2: Append to internal buffer
    internal_buffer_.insert(internal_buffer_.end(), input_data, input_data + input_size);

    // Step 3 & 4: Process in chunks appropriate for model input size
    while (internal_buffer_.size() >= frame_length_) {
        // Get a chunk for inference
        std::vector<int16_t> frame(internal_buffer_.begin(), internal_buffer_.begin() + frame_length_);

        // Run inference using multinet model
        int keyword_id = multinet_model_->RunInference(frame);

        // Validate detection result
        if (keyword_id >= 0 && IsConfident(keyword_id)) {  // Assume IsConfident() checks threshold internally
            // Step 5: Invoke callback and deactivate
            if (on_wake_word_detected_) {
                on_wake_word_detected_(keyword_id);
            }
            is_active_ = false;
            internal_buffer_.clear();  // Clear remaining data after detection
            return;
        }

        // Shift buffer forward by hop length (overlap-add style)
        internal_buffer_.erase(internal_buffer_.begin(), internal_buffer_.begin() + hop_length_);
    }
}

