void AfeWakeWord::EncodeWakeWordData() {
    // Step 1: Allocate memory for task stack and buffer if not done already
    if (!wake_word_encode_task_stack_) {
        wake_word_encode_task_stack_ = static_cast<StackType_t*>(heap_caps_malloc(
            CONFIG_WAKE_WORD_ENCODE_STACK_SIZE * sizeof(StackType_t),
            MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT));
        if (!wake_word_encode_task_stack_) {
            ESP_LOGE("AfeWakeWord", "Failed to allocate stack for wake word encoding task");
            return;
        }
    }

    if (!wake_word_encode_task_buffer_) {
        wake_word_encode_task_buffer_ = static_cast<StaticTask_t*>(heap_caps_malloc(
            sizeof(StaticTask_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT));
        if (!wake_word_encode_task_buffer_) {
            ESP_LOGE("AfeWakeWord", "Failed to allocate task buffer for wake word encoding task");
            return;
        }
    }

    // Step 2: Create task to perform actual encoding asynchronously
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            AfeWakeWord* self = static_cast<AfeWakeWord*>(arg);

            // Initialize Opus Encoder
            int error;
            OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, &error);
            if (error != OPUS_OK || !encoder) {
                ESP_LOGE("AfeWakeWord", "Failed to create Opus encoder: %s", opus_strerror(error));
                vTaskDelete(nullptr);
                return;
            }

            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));
            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1)); // Low complexity
            opus_encoder_ctl(encoder, OPUS_SET_SIGNAL(OPUS_SIGNAL_VOICE));

            constexpr size_t kFrameSize = 160;       // 10ms @ 16kHz
            constexpr size_t kMaxPacketSize = 1275;   // Max possible Opus frame size
            std::vector<uint8_t> output_buffer(kMaxPacketSize);

            {
                std::unique_lock<std::mutex> lock(self->wake_word_mutex_);

                // Step 3 & 4: Encode all available PCM segments
                while (!self->wake_word_pcm_.empty()) {
                    auto& pcm_segment = self->wake_word_pcm_.front();

                    for (size_t offset = 0; offset < pcm_segment.size(); offset += kFrameSize) {
                        size_t remaining_samples = pcm_segment.size() - offset;
                        size_t samples_to_encode = std::min(kFrameSize, remaining_samples);

                        int encoded_bytes = opus_encode(encoder,
                                                        pcm_segment.data() + offset,
                                                        samples_to_encode,
                                                        output_buffer.data(),
                                                        kMaxPacketSize);

                        if (encoded_bytes > 0) {
                            std::vector<uint8_t> encoded_packet(output_buffer.begin(),
                                                               output_buffer.begin() + encoded_bytes);
                            self->wake_word_opus_.push_back(std::move(encoded_packet));
                        } else {
                            ESP_LOGW("AfeWakeWord", "Opus encoding failed: %s", opus_strerror(encoded_bytes));
                        }
                    }

                    self->wake_word_pcm_.pop_front();
                }

                // Step 5: Signal availability of encoded data
                self->wake_word_cv_.notify_all();
            }

            // Step 6: Append termination marker
            const uint8_t termination_marker[] = {0x00};
            self->wake_word_opus_.emplace_back(termination_marker, termination_marker + sizeof(termination_marker));

            opus_encoder_destroy(encoder);
            vTaskDelete(nullptr);
        },
        "WakeWordEncode",
        CONFIG_WAKE_WORD_ENCODE_STACK_SIZE,
        this,
        5,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (!wake_word_encode_task_) {
        ESP_LOGE("AfeWakeWord", "Failed to create wake word encoding task");
    }
}

