bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus) {
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data in the queue
    wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

    // Retrieve and swap the front buffer to minimize copy
    opus.swap(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // Unlock happens automatically at end of scope

    // Return success based on whether the retrieved data is non-empty
    return !opus.empty();
}

