    // Define register addresses
    const uint8_t REG_CONFIG_PORT0 = 0x06;
    const uint8_t REG_CONFIG_PORT1 = 0x07;

    // Set both ports as outputs (0x00 means all pins are outputs)
    uint8_t config_port0_data[] = {REG_CONFIG_PORT0, 0x00};
    uint8_t config_port1_data[] = {REG_CONFIG_PORT1, 0x00};

    // Write configuration to Port 0
