static void IRAM_ATTR boot_button_isr_handler(void* arg) {
    static TickType_t last_interrupt_time = 0;
    TickType_t interrupt_time = xTaskGetTickCountFromISR();

    // Simple software debouncing
    if ((interrupt_time - last_interrupt_time) > pdMS_TO_TICKS(DEBOUNCE_DELAY_MS)) {
        BaseType_t xHigherPriorityTaskWoken = pdFALSE;

        // Determine which mode to act upon
        EventBits_t bits = xEventGroupGetBitsFromISR(app_event_group);
        if (!(bits & APP_STARTED_BIT)) {
            // Startup phase -> Trigger Wi-Fi Config
            xEventGroupSetBitsFromISR(app_event_group, WIFI_CONFIG_BIT, &xHigherPriorityTaskWoken);
        } else {
            // Normal mode -> Toggle Chat
            xEventGroupSetBitsFromISR(app_event_group, CHAT_TOGGLE_BIT, &xHigherPriorityTaskWoken);
        }

        portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
    }
    last_interrupt_time = interrupt_time;
}

