    gpio_set_level(CAMERA_PWR_CTRL_PIN, 1); // Turn on power
    vTaskDelay(10 / portTICK_PERIOD_MS);    // Wait for stabilization

    gpio_set_level(CAMERA_RESET_PIN, 0);    // Assert reset
