void audio_wifi_config::FrequencyDetector::ProcessSample(float sample) {
    // Compute the next value in the recurrence relation:
    // S[n] = sample + filter_coefficient_ * S[n-1] - S[n-2]
    float s_n = sample + filter_coefficient_ * state_buffer_[1] - state_buffer_[0];

    // Update the state buffer:
    // Remove the oldest sample and add the newest one
    state_buffer_.pop_front();
    state_buffer_.push_back(s_n);
}

float FrequencyDetector::GetAmplitude() const {
    // Ensure that there are at least two samples in the buffer
    if (state_.size() < 2) {
        return 0.0f;
    }

    // Access the last two signal samples
    float sample_n = state_[state_.size() - 1];
    float sample_n1 = state_[state_.size() - 2];

    // Compute real and imaginary components using cosine and sine coefficients
    float real = sample_n * cos_coeff_ + sample_n1 * cos_coeff_;
    float imag = sample_n * sin_coeff_ + sample_n1 * sin_coeff_;

    // Calculate squared magnitudes
    float real_sq = real * real;
    float imag_sq = imag * imag;

    // Sum of squares
    float sum_squares = real_sq + imag_sq;

    // Take square root and normalize by half the window size
    float amplitude = sqrtf(sum_squares) / (window_size_ * 0.5f);

    return amplitude;
}

