#include <vector>
#include <cmath>

// Constants for AFSK frequencies and sampling parameters
constexpr float kSampleRateHz = 8000.0f;
constexpr int kWindowSize = 240; // ~30ms at 8kHz
constexpr float kMarkFreqHz = 1200.0f;
constexpr float kSpaceFreqHz = 2200.0f;

// Helper function implementing the Goertzel algorithm
float ComputeGoertzelEnergy(const std::vector<float>& buffer, float target_freq_hz) {
    const int N = static_cast<int>(buffer.size());
    const float k = (N * target_freq_hz) / kSampleRateHz;
    const float w = (2.0f * M_PI * k) / N;
    const float cos_w = std::cos(w);
    const float coeff = 2.0f * cos_w;

    float q0 = 0.0f, q1 = 0.0f, q2 = 0.0f;

    for (int n = 0; n < N; ++n) {
        q0 = coeff * q1 - q2 + buffer[n];
        q2 = q1;
        q1 = q0;
    }

    // Calculate real and imaginary parts for magnitude squared
    float real = q1 - q2 * cos_w;
    float imag = q2 * std::sin(w);

    return real * real + imag * imag; // Energy estimate
}

// Main function implementation
std::vector<float> ProcessAudioSamples(const std::vector<float>& input_samples) {
    std::vector<float> probabilities;

    int num_windows = input_samples.size() / kWindowSize;

    for (int i = 0; i < num_windows; ++i) {
        // Extract windowed samples
        std::vector<float> window(input_samples.begin() + i * kWindowSize,
                                  input_samples.begin() + (i + 1) * kWindowSize);

        // Apply Goertzel algorithm to get energy estimates
        float mark_energy = ComputeGoertzelEnergy(window, kMarkFreqHz);
        float space_energy = ComputeGoertzelEnergy(window, kSpaceFreqHz);

        // Avoid division by zero
        float total_energy = mark_energy + space_energy;
        float prob = (total_energy > 0.0f) ? (mark_energy / total_energy) : 0.0f;

        probabilities.push_back(prob);
    }

    return probabilities;
}

