enum class TransmissionState {
    INACTIVE,
    WAITING_FOR_START,
    RECEIVING_DATA
};

static TransmissionState current_state = TransmissionState::INACTIVE;
static std::vector<uint8_t> received_data; // Stores decoded bytes during reception
static std::vector<bool> bit_buffer;       // Temporary storage for individual bits
static const uint8_t START_IDENTIFIER[] = {0xAA, 0xBB}; // Example start ID
static const uint8_t END_IDENTIFIER[] = {0xCC, 0xDD};   // Example end ID

// Helper to check if last N bits match a pattern
bool MatchPattern(const std::vector<bool>& buffer, const uint8_t* pattern, size_t pattern_len_bits) {
    if (buffer.size() < pattern_len_bits) return false;

    for (size_t i = 0; i < pattern_len_bits; ++i) {
        bool expected_bit = (pattern[i / 8] >> (7 - (i % 8))) & 1;
        if (buffer[buffer.size() - pattern_len_bits + i] != expected_bit)
            return false;
    }
    return true;
}

// Converts accumulated bits into a byte when enough bits are present
void FlushBitsToBytes() {
    while (bit_buffer.size() >= 8) {
        uint8_t byte_val = 0;
        for (int i = 0; i < 8; ++i) {
            byte_val <<= 1;
            byte_val |= bit_buffer.front();
            bit_buffer.erase(bit_buffer.begin());
        }

        switch (current_state) {
            case TransmissionState::WAITING_FOR_START:
                received_data.push_back(byte_val);
                // Check if we've matched the start identifier
                if (received_data.size() >= sizeof(START_IDENTIFIER)) {
                    bool matches = true;
                    for (size_t i = 0; i < sizeof(START_IDENTIFIER); ++i) {
                        if (received_data[received_data.size() - sizeof(START_IDENTIFIER) + i] != START_IDENTIFIER[i]) {
                            matches = false;
                            break;
                        }
                    }
                    if (matches) {
                        current_state = TransmissionState::RECEIVING_DATA;
                        received_data.clear(); // Clear after recognizing start ID
                    }
                }
                break;

            case TransmissionState::RECEIVING_DATA:
                received_data.push_back(byte_val);

                // Check for end identifier
                if (received_data.size() >= sizeof(END_IDENTIFIER)) {
                    bool matches = true;
                    for (size_t i = 0; i < sizeof(END_IDENTIFIER); ++i) {
                        if (received_data[received_data.size() - sizeof(END_IDENTIFIER) + i] != END_IDENTIFIER[i]) {
                            matches = false;
                            break;
                        }
                    }
                    if (matches) {
                        // Optionally perform checksum here
                        // ...

                        // Reset to inactive state
                        current_state = TransmissionState::INACTIVE;
                        received_data.clear();
                    }
                }
                break;

            default:
                break;
        }
    }
}

void ProcessProbabilityData(const std::vector<float>& probabilities, float threshold) {
    for (float prob : probabilities) {
        bool bit = (prob >= threshold);
        bit_buffer.push_back(bit);

        // Try to flush bits into bytes whenever possible
        FlushBitsToBytes();

        // Handle initial transition from INACTIVE -> WAITING
        if (current_state == TransmissionState::INACTIVE && !bit_buffer.empty()) {
            current_state = TransmissionState::WAITING_FOR_START;
        }
    }
}

std::vector<uint8_t> AfskDemod::ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    // Validate input length
    if (bits.size() % 8 != 0) {
        // Handle invalid input - could assert, throw exception, or return empty vector
        return {}; // Returning empty vector to indicate failure
    }

    std::vector<uint8_t> bytes;
    size_t num_bytes = bits.size() / 8;
    bytes.reserve(num_bytes);

    for (size_t i = 0; i < num_bytes; ++i) {
        uint8_t byte = 0;
        for (int bit_index = 0; bit_index < 8; ++bit_index) {
            // Assuming bits are ordered with LSB last (i.e., bit 0 is last in group)
            byte |= (bits[i * 8 + bit_index] & 1) << (7 - bit_index);
        }
        bytes.push_back(byte);
    }

    return bytes;
}

