void Backlight::OnTransitionTimer() {
    // Step 1: Check if current brightness equals target brightness
    if (brightness_ == target_brightness_) {
        // Step 2: Stop the transition timer if brightness levels match
        esp_timer_stop(transition_timer_);
        return;
    }

    // Step 3: Calculate incremental brightness adjustment based on transition speed
    if (brightness_ < target_brightness_) {
        brightness_ += step_;
        if (brightness_ > target_brightness_) {
            brightness_ = target_brightness_;
        }
    } else {
        brightness_ -= step_;
        if (brightness_ < target_brightness_) {
            brightness_ = target_brightness_;
        }
    }

    // Step 4 & 5: Update the current brightness value and apply it to hardware
    SetBrightnessImpl(brightness_);
}

