void PwmBacklight::SetBrightnessImpl(uint8_t brightness) {
    // Step 1: Clamp the brightness value to valid range [0, 100]
    if (brightness > 100) {
        brightness = 100;
    }

    // Step 2: Map brightness percentage (0-100) to 10-bit PWM range (0-1023)
    uint32_t duty = (static_cast<uint32_t>(brightness) * 1023) / 100;

    // Step 3: Update the LEDC channel with the new duty cycle
    // Assuming LEDC channel parameters are predefined or accessible via class members
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty);
    ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
}

