#include <cstdio>
#include "esp_system.h" // For esp_random()

std::string Board::GenerateUuid() {
    uint8_t uuid[16];

    // Step 1 & 2: Fill 16 bytes with random values using ESP32's hardware RNG
    uint32_t* words = reinterpret_cast<uint32_t*>(uuid);
    for (int i = 0; i < 4; ++i) {
        words[i] = esp_random();
    }

    // Step 3: Set version to 4 (bits 12-15 of byte 6)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Step 4: Set variant to RFC 4122 (bits 6-7 of byte 8 to 10xx)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Step 5: Format UUID as 36-character string with hyphens
    char uuidStr[37]; // 36 chars + null terminator
    snprintf(uuidStr, sizeof(uuidStr),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuidStr);
}

