    mcp_server.AddTool("self.set_press_to_talk",
        "Switch between press to talk mode (长按说话) and click to talk mode (单击说话).\n"
        "The mode can be `press_to_talk` or `click_to_talk`.",
        PropertyList({
            Property("mode", kPropertyTypeString)
        }),
