std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "";
    }

    // Hardware information
    cJSON *hardware = cJSON_CreateObject();
    if (hardware != NULL) {
        // Chip model
        #ifdef CONFIG_IDF_TARGET_ESP32
            cJSON_AddStringToObject(hardware, "chip_model", "ESP32");
        #elif defined(CONFIG_IDF_TARGET_ESP32S2)
            cJSON_AddStringToObject(hardware, "chip_model", "ESP32-S2");
        #elif defined(CONFIG_IDF_TARGET_ESP32S3)
            cJSON_AddStringToObject(hardware, "chip_model", "ESP32-S3");
        #elif defined(CONFIG_IDF_TARGET_ESP32C3)
            cJSON_AddStringToObject(hardware, "chip_model", "ESP32-C3");
        #else
            cJSON_AddStringToObject(hardware, "chip_model", "Unknown");
        #endif

        // Flash size
        cJSON_AddNumberToObject(hardware, "flash_size", ESP.flashSize());

        // MAC address
        uint8_t mac[6];
        esp_read_mac(mac, ESP_MAC_WIFI_STA);
        char mac_str[18];
        snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
                 mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
        cJSON_AddStringToObject(hardware, "mac_address", mac_str);

        cJSON_AddItemToObject(root, "hardware", hardware);
    }

    // Application metadata
    cJSON *app = cJSON_CreateObject();
    if (app != NULL) {
        // Get application description
        const esp_app_desc_t *app_desc = esp_app_get_description();
        if (app_desc != NULL) {
            cJSON_AddStringToObject(app, "name", app_desc->project_name);
            cJSON_AddStringToObject(app, "version", app_desc->version);
            cJSON_AddStringToObject(app, "compile_time", app_desc->date " " app_desc->time);
        }

        cJSON_AddItemToObject(root, "application", app);
    }

    // Memory information
    cJSON *memory = cJSON_CreateObject();
    if (memory != NULL) {
        cJSON_AddNumberToObject(memory, "min_free_heap", heap_caps_get_minimum_free_size(MALLOC_CAP_DEFAULT));
        cJSON_AddNumberToObject(memory, "free_heap", esp_get_free_heap_size());
        cJSON_AddNumberToObject(memory, "total_heap", heap_caps_get_total_size(MALLOC_CAP_DEFAULT));

        cJSON_AddItemToObject(root, "memory", memory);
    }

    // Partition information
    cJSON *partition = cJSON_CreateObject();
    if (partition != NULL) {
        // Get current running partition
        const esp_partition_t *running = esp_ota_get_running_partition();
        if (running != NULL) {
            cJSON_AddStringToObject(partition, "running_partition", running->label);
            cJSON_AddNumberToObject(partition, "partition_size", running->size);
        }

        // Get boot partition
        const esp_partition_t *boot = esp_ota_get_boot_partition();
        if (boot != NULL) {
            cJSON_AddStringToObject(partition, "boot_partition", boot->label);
        }

        cJSON_AddItemToObject(root, "partition", partition);
    }

    // Device UUID
    cJSON_AddStringToObject(root, "uuid", GetUuid().c_str());

    // Board type
    cJSON_AddStringToObject(root, "board_type", GetBoardType().c_str());

    // Convert to string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result;
    if (json_string != NULL) {
        result = std::string(json_string);
        cJSON_free(json_string);
    }

    cJSON_Delete(root);
    return result;
}

#include "button_adc.h"
