// Assuming these exist globally or defined elsewhere
extern adc_oneshot_unit_handle_t adc_handle;
extern const adc_oneshot_chan_cfg_t channel_config;

class AdcButton {
private:
    button_handle_t m_button_handle;

public:
    // Constructor definition
    explicit AdcButton(const button_adc_config_t& config) {
        // Step 1: Validate configuration
        if (!config.adc_unit || !config.channel || config.button_index >= MAX_BUTTON_NUM) {
            // Log error or assert here depending on environment
            return;
        }

        // Step 2: Initialize ADC GPIO and channel
        adc_oneshot_io_param_t io_config = {
            .unit_id = config.adc_unit,
            .channel = config.channel,
            .gpio_num = config.gpio_num
        };

        ESP_ERROR_CHECK(adc_oneshot_config_channel(adc_handle, config.channel, &channel_config));

        // Optional: Set GPIO as input (analog)
        gpio_set_direction(static_cast<gpio_num_t>(config.gpio_num), GPIO_MODE_INPUT);

        // Step 3 & 4: Create button instance and register callbacks via IoT Button Framework
        button_config_t btn_cfg = {
            .type = BUTTON_ADC,
            .adc_button = {
                .adc_handle = adc_handle,
                .channel = config.channel,
                .button_index = config.button_index
            }
        };

        m_button_handle = iot_button_create(&btn_cfg);
        if (m_button_handle == NULL) {
            // Handle failure gracefully
            return;
        }

        // Register default press types (SHORT and LONG at 2 sec threshold)
        iot_button_add_on_press_cb(m_button_handle, 2000, button_long_press_cb, this);
        iot_button_add_on_release_cb(m_button_handle, button_short_press_cb, this);

        // Step 5: Store handle internally
        // Already stored in m_button_handle
    }

    ~AdcButton() {
        if (m_button_handle) {
            iot_button_delete(m_button_handle);
        }
    }

    // Dummy callback placeholders
    static void button_long_press_cb(void* arg, void* usr_data) {
        AdcButton* self = static_cast<AdcButton*>(usr_data);
        // Handle long press action
