void WifiBoard::StartNetwork() {
    // Step 1: Get references to required components
    auto* led = Board::GetInstance().GetLed();
    auto* display = Board::GetInstance().GetDisplay();
    auto* network = Board::GetInstance().GetNetwork();

    if (!led || !display || !network) {
        ESP_LOGE("WifiBoard", "Required hardware component is missing.");
        return;
    }

    // Step 2: Initialize WiFi Manager with SSID prefix and language
    const std::string ssid_prefix = "MyDevice";
    const std::string language = "en"; // Or fetch dynamically

    network->Initialize(ssid_prefix, language);

    // Step 3: Set up unified event callback
    network->SetEventCallback([this, led, display](NetworkEvent event, const std::string& data) {
        switch (event) {
            case NetworkEvent::Scanning:
                led->SetPattern(LedPattern::BLINK_SLOW);
                display->SetStatus(Lang::Strings::SCANNING);
                break;

            case NetworkEvent::Connecting:
                led->SetPattern(LedPattern::BLINK_FAST);
                display->SetStatus(Lang::Strings::CONNECTING + " " + data);
                break;

            case NetworkEvent::Connected:
                led->SetPattern(LedPattern::SOLID);
                display->SetStatus(Lang::Strings::CONNECTED + " " + data);
                break;

            case NetworkEvent::Disconnected:
                led->SetPattern(LedPattern::OFF);
                display->SetStatus(Lang::Strings::DISCONNECTED);
                break;

            case NetworkEvent::WifiConfigModeEnter:
                led->SetPattern(LedPattern::BLINK_VERY_SLOW);
                display->SetStatus(Lang::Strings::CONFIG_MODE_ENTER);
                break;

            case NetworkEvent::WifiConfigModeExit:
                led->SetPattern(LedPattern::OFF);
                display->SetStatus(Lang::Strings::CONFIG_MODE_EXIT);
                break;

            default:
                break;
        }
    });

    // Step 4: Attempt to connect using saved credentials
    bool connected = network->Connect();

    // Step 5: Enter config mode if connection failed
    if (!connected) {
        network->StartConfigurationMode();
    }
}

