    return ConfigManager::GetString("wifi.ssid", "");
}

std::string GetSavedPassword() {
    // Retrieve password from NVS or config store
    return ConfigManager::GetString("wifi.password", "");
}

void ConnectToWiFi(const std::string& ssid, const std::string& password) {
    // Use platform-specific WiFi driver to initiate connection
    WifiInterface::Connect(ssid, password);
}

void EnterConfigurationMode() {
    // Activate soft AP or web server for user input
    WifiConfigurator::StartConfigurationMode();
    AppState::Set(AppState::kWifiConfiguring);
}

void RegisterNetworkHandlers() {
    // Register callbacks for various network states
    NetworkEventManager::Subscribe(NetworkEvent::Connected, [](const std::string&) {
        AppState::Set(AppState::kOnline);
    });
    NetworkEventManager::Subscribe(NetworkEvent::Disconnected, [](const std::string&) {
        AppState::Set(AppState::kOffline);
    });
}

void TryWifiConnect() {
    RegisterNetworkHandlers();

    if (!HasStoredCredentials()) {
        // No credentials found; go straight into configuration mode
        std::this_thread::sleep_for(std::chrono::seconds(2)); // Brief delay as per requirement
        EnterConfigurationMode();
        return;
    }

    std::string ssid = GetSavedSSID();
    std::string password = GetSavedPassword();

    // Indicate connecting status
    AppState::Set(AppState::kConnecting);

    ConnectToWiFi(ssid, password);

    // Wait briefly for connection attempt outcome
    std::this_thread::sleep_for(std::chrono::seconds(10));

    if (!NetworkStateManager::IsConnected()) {
        // Connection failed - delay and start config mode
        std::this_thread::sleep_for(std::chrono::milliseconds(500));
        EnterConfigurationMode();
    }
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string& data) {
    switch(event) {
        case NetworkEvent::kConnected:
            SetConnected(true);
            StopReconnectTimer();
            ReleaseProvisioningResources();
            break;

        case NetworkEvent::kDisconnected:
            SetConnected(false);
            break;

        case NetworkEvent::kScanningStarted:
            // Can be extended later if needed
            break;

        case NetworkEvent::kConfigurationModeEntered:
            SetInConfigMode(true);
            break;

        case NetworkEvent::kConfigurationModeExited:
            SetInConfigMode(false);
            if (!IsConnected()) {
                TriggerReconnectAttempt();
            }
            break;

        default:
            // Ignore unrecognized events
            break;
    }

    // Notify any registered external callback
    if (event_callback_) {
        event_callback_(event, data);
    }
}

void OnWifiConnectTimeout(void *arg) {
    // Step 1: Stop the current WiFi station mode operation
    WiFiStationStop();

    // Step 2: Transition device to configuration mode for network reconfiguration
    EnterConfigMode();

    // Step 3: Update system state to reflect setup mode transition
    SetSystemState(STATE_SETUP);

    // Step 4: Notify UI/display layer about the configuration mode activation
    NotifyUI_ConfigModeEntered();

    // Step 5: Log timeout event and initiate recovery procedure
    LOG_ERROR("WiFi connection timed out. Entered configuration mode.");
    RecoveryInitiate();
}

