    ESP_LOGI(TAG, "Starting SoftAP provisioning");
    WifiManager::GetInstance().StartSoftAP();
#elif defined(CONFIG_WIFI_PROV_BLE_BLUFI)
    ESP_LOGI(TAG, "Starting BLE Blufi provisioning");
    BleBlufi::Start();
#elif defined(CONFIG_WIFI_PROV_ACOUSTIC)
    ESP_LOGI(TAG, "Starting acoustic provisioning");
    AcousticProv::Start();
