NetworkInterface* WifiBoard::GetNetwork() {
    // Check if the network singleton instance already exists
    if (network_ == nullptr) {
        // Initialize the ESP32-based network interface
        network_ = std::make_unique<Esp32NetworkInterface>();

        // Configure WiFi settings and event handlers
        network_->Initialize();

        // Set up event callbacks for network state changes
        network_->SetEventHandler([this](NetworkEvent event, const std::string& data) {
            if (network_event_callback_) {
                network_event_callback_(event, data);
            }
        });

        // Start the network connection process
        network_->Start();
    }

    // Return the pointer to the initialized network instance
    return network_.get();
}

