const char* WifiBoard::GetNetworkStateIcon() {
    // Get network interface
    NetworkInterface* network = GetNetwork();
    if (!network) {
        return FONT_AWESOME_WIFI_SLASH;
    }

    // Check if device is in configuration mode
    if (network->IsInConfigMode()) {
        return FONT_AWESOME_WIFI_GEAR;
    }

    // Check network connection status
    if (!network->IsConnected()) {
        return FONT_AWESOME_WIFI_SLASH;
    }

    // Device is connected, assess signal strength
    int signal_strength = network->GetSignalStrength();

    // Map signal strength to quality levels
    if (signal_strength >= -50) {
        // Strong signal (-50 dBm or better)
        return FONT_AWESOME_WIFI_STRONG;
    } else if (signal_strength >= -70) {
        // Fair signal (-50 to -70 dBm)
        return FONT_AWESOME_WIFI_FAIR;
    } else {
        // Weak signal (-70 dBm or worse)
        return FONT_AWESOME_WIFI_WEAK;
    }
}

