std::string WifiBoard::GetBoardJson() {
    std::string json = "{";

    // Add board type and name
    json += "\"type\":\"" + GetBoardType() + "\",";

    // Add MAC address
    std::string mac_address = SystemInfo::GetMacAddress();
    json += "\"mac_address\":\"" + mac_address + "\"";

    // Check if we're not in configuration mode to add Wi-Fi details
    NetworkInterface* network = GetNetwork();
    if (network && !network->IsInConfigMode()) {
        // Add Wi-Fi details
        json += ",\"wifi\":{";

        // Add SSID
        std::string ssid = network->GetSsid();
        json += "\"ssid\":\"" + ssid + "\",";

        // Add RSSI
        int rssi = network->GetRssi();
        json += "\"rssi\":" + std::to_string(rssi) + ",";

        // Add channel
        int channel = network->GetChannel();
        json += "\"channel\":" + std::to_string(channel) + ",";

        // Add IP address
        std::string ip = network->GetIpAddress();
        json += "\"ip_address\":\"" + ip + "\"";

        json += "}";
    }

    json += "}";

    return json;
}

