#include "wifi_board.h"
#include "esp_wifi.h"
#include "esp_log.h"

// Assuming PowerSaveLevel is defined somewhere globally or in board.h
// Example assumed definition:
// enum class PowerSaveLevel {
//     LOW_POWER,
//     BALANCED,
//     PERFORMANCE
// };

void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level) {
    wifi_ps_type_t ps_type;

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            ps_type = WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            // Medium modem power saving balances performance & battery life
            ps_type = WIFI_PS_MAX_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            ps_type = WIFI_PS_NONE;
            break;
        default:
            ESP_LOGW("WifiBoard", "Unknown PowerSaveLevel: %d", static_cast<int>(level));
            return;
    }

    esp_err_t err = esp_wifi_set_ps(ps_type);
    if (err != ESP_OK) {
        ESP_LOGE("WifiBoard", "Failed to set Wi-Fi power save level: %s", esp_err_to_name(err));
    } else {
        ESP_LOGI("WifiBoard", "Successfully set Wi-Fi power save level to %d", static_cast<int>(ps_type));
    }
}

