std::string WifiBoard::GetDeviceStatusJson() {
    // Initialize JSON object structure for device status
    cJSON* root = cJSON_CreateObject();

    // Retrieve and append audio speaker volume from AudioCodec module
    auto audio_codec = GetAudioCodec();
    if (audio_codec) {
        int volume = audio_codec->GetOutputVolume();
        cJSON_AddNumberToObject(root, "audio_speaker_volume", volume);
    }

    // Fetch display brightness and theme information from Display module
    auto backlight = GetBacklight();
    if (backlight) {
        uint8_t brightness = backlight->GetBrightness();
        cJSON_AddNumberToObject(root, "screen_brightness", brightness);
    }

    auto display = GetDisplay();
    if (display) {
        const char* theme = display->GetThemeName(); // Assuming this method exists
        if (theme) {
            cJSON_AddStringToObject(root, "screen_theme", theme);
        }
    }

    // Collect battery level and charging state from Power Management subsystem
    int battery_level = 0;
    bool charging = false;
    bool discharging = false;
    if (GetBatteryLevel(battery_level, charging, discharging)) {
        cJSON_AddNumberToObject(root, "battery_level", battery_level);
        cJSON_AddBoolToObject(root, "battery_charging", charging);
    }

    // Gather WiFi SSID and signal strength through NetworkInterface module
    auto network = GetNetwork();
    if (network) {
        std::string ssid = network->GetSsid();
        int rssi = network->GetRssi();

        if (!ssid.empty()) {
            cJSON_AddStringToObject(root, "wifi_ssid", ssid.c_str());
        }
        cJSON_AddNumberToObject(root, "wifi_signal_strength", rssi);
    }

    // Read chip temperature sensor and finalize JSON output string
    float temperature = 0.0f;
    if (GetTemperature(temperature)) {
        cJSON_AddNumberToObject(root, "chip_temperature", temperature);
    }

    // Serialize all data to JSON
    char* json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string ? json_string : "{}");

    if (json_string) {
        free(json_string);
    }
    cJSON_Delete(root);

    return result;
}

