void SingleLed::TurnOn() {
    // Step 1: Acquire mutex lock to ensure thread-safe access to the LED state
    std::lock_guard<std::mutex> lock(mutex_);

    // Step 2: Stop any active blink timer to prevent interference with steady ON state
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
    }

    // Step 3: Set the LED color to the configured RGB values
    if (led_strip_ != nullptr) {
        led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
    }

    // Step 4: Refresh the LED strip to immediately reflect the new color
    if (led_strip_ != nullptr) {
        led_strip_refresh(led_strip_);
    }
}

