void SingleLed::TurnOff() {
    // Step 1: Acquire mutex lock for thread safety
    std::lock_guard<std::mutex> lock(mutex_);

    // Step 2: Null check for LED strip initialization
    if (led_strip_ == nullptr) {
        return;
    }

    // Step 3: Stop any active blinking timer
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
    }

    // Step 4: Clear the LED strip state (turn off)
    led_strip_set_pixel(led_strip_, 0, 0, 0, 0);  // Set pixel 0 to black (off)
    led_strip_refresh(led_strip_);                // Apply change

    // Optional: Reset internal color tracking
    r_ = 0;
    g_ = 0;
    b_ = 0;
}

#include "single_led.h"
#include <stdint.h>

// Assume these external dependencies exist
extern bool isLedInitialized;
extern void toggleLed();
extern void* createPeriodicTimer(const char* name, uint32_t periodMs, void (*callback)(void*));
extern void startTimer(void* timerHandle);
extern void stopAndDeleteTimer(void* timerHandle);

// Static/global variables to hold state
static int g_blinkCount = 0;
static int g_intervalMs = 0;
static bool g_isLedOn = false;
static void* g_timerHandle = nullptr;

// Forward declaration of the timer callback
void blinkTimerCallback(void* timer);

// Function implementation
void StartBlinkTask(int blinkCount, int intervalMs) {
    // Step 1: Check if LED is initialized
    if (!isLedInitialized) {
        return;
    }

    // Step 2: Set up blink parameters
    g_blinkCount = blinkCount * 2; // Each full blink = ON + OFF
    g_intervalMs = intervalMs;

    // Reset LED state
    g_isLedOn = false;

    // Step 3: Create and start the periodic timer
    if (g_timerHandle == nullptr) {
        g_timerHandle = createPeriodicTimer("BlinkTimer", g_intervalMs, blinkTimerCallback);
    }
    if (g_timerHandle != nullptr) {
        startTimer(g_timerHandle);
    }
}

// Timer callback function
void blinkTimerCallback(void* timer) {
    // Step 4: Toggle LED and decrement blink count
    toggleLed();
    g_blinkCount--;

    // Step 5: Clean up when done
    if (g_blinkCount <= 0) {
        stopAndDeleteTimer(timer);
        g_timerHandle = nullptr;
    }
}

