void SingleLed::OnBlinkTimer() {
    std::lock_guard<std::mutex> lock(mutex_);

    if (blink_counter_ > 0) {
        blink_counter_--;

        // Toggle LED state based on blink counter parity
        if (blink_counter_ % 2 == 0) {
            // Turn ON - Set to white light (or any default color)
            r_ = 255;
            g_ = 255;
            b_ = 255;
        } else {
            // Turn OFF - Clear color
            r_ = 0;
            g_ = 0;
            b_ = 0;
        }

        // Apply updated color to LED
        led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
        led_strip_refresh(led_strip_);

        // Stop timer when blink sequence completes
        if (blink_counter_ == 0) {
            esp_timer_stop(blink_timer_);
        }
    }
}

