void SingleLed::OnStateChanged() {
    DeviceState state = GetDeviceState();

    // Clear any ongoing blink timers/tasks before changing state
    if (blink_timer_) {
        esp_timer_stop(blink_timer_);
    }

    switch (state) {
        case kDeviceStateUnknown:
            SetColor(128, 0, 128); // Purple
            StartContinuousBlink(1000); // Slow blink
            break;

        case kDeviceStateStarting:
            SetColor(0, 0, 255); // Blue
            StartContinuousBlink(200); // Fast blink
            break;

        case kDeviceStateWifiConfiguring:
            SetColor(255, 255, 0); // Yellow
            StartContinuousBlink(500);
            break;

        case kDeviceStateIdle:
            SetColor(0, 255, 0); // Green
            TurnOn(); // Solid green
            break;

        case kDeviceStateConnecting:
            SetColor(0, 255, 255); // Cyan
            StartContinuousBlink(750); // Medium blink
            break;

        case kDeviceStateListening:
            SetColor(255, 255, 255); // White
            StartContinuousBlink(100); // Simulate pulsing
            break;

        case kDeviceStateSpeaking:
            SetColor(255, 165, 0); // Orange
            TurnOn(); // Solid orange
            break;

        case kDeviceStateUpgrading:
            SetColor(255, 0, 255); // Magenta
            StartContinuousBlink(100); // Very fast blink
            break;

        case kDeviceStateActivating:
            SetColor(255, 255, 255); // White again
            StartContinuousBlink(300); // Moderate alternating
            break;

        default:
            TurnOff(); // Off for undefined states
            break;
    }
}

