    esp_mqtt_client_handle_t mqtt_client;
    StaticTimer_t reconnect_timer_buffer;
    TimerHandle_t reconnect_timer;

    static void ReconnectTimerCallback(TimerHandle_t xTimer);
};

// Constructor implementation
MqttProtocol::MqttProtocol() {
    // Step 1: Initialize event group for MQTT synchronization
    mqtt_event_group = xEventGroupCreate();
    if (mqtt_event_group == NULL) {
        // Handle error - failed to create event group
        return;
    }

    // Step 2: Configure reconnect timer with idle state detection
    const TickType_t RECONNECT_PERIOD_MS = pdMS_TO_TICKS(5000); // e.g., every 5 seconds
    reconnect_timer = xTimerCreateStatic(
        "MqttReconnectTimer",
        RECONNECT_PERIOD_MS,
        pdTRUE,                    // Auto-reload
        this,                      // Timer ID (pass instance)
        ReconnectTimerCallback,    // Callback function
        &reconnect_timer_buffer    // Pre-allocated buffer
    );

    if (reconnect_timer == NULL) {
        // Handle error - failed to create timer
        vEventGroupDelete(mqtt_event_group);
        return;
    }

    // Start the timer
    if (xTimerStart(reconnect_timer, 0) != pdPASS) {
        // Handle error starting timer
        xTimerDelete(reconnect_timer, 0);
        vEventGroupDelete(mqtt_event_group);
        return;
    }

    // Step 3 & 4: Retry mechanism + Device state awareness handled inside callback
}

// Static member function acting as timer callback
void MqttProtocol::ReconnectTimerCallback(TimerHandle_t xTimer) {
    MqttProtocol* self = static_cast<MqttProtocol*>(pvTimerGetTimerID(xTimer));

    // Step 4: Integrate device state awareness into reconnection logic
    if (!DeviceStateManager::getInstance().isIdle()) {
        // Do not attempt reconnect if device is not idle
        return;
    }

    // Step 3: Register scheduled retry mechanism via task scheduler
    Scheduler::getInstance().postDelayed([](void* context) {
        MqttProtocol* protocol = static_cast<MqttProtocol*>(context);

        // Attempt to reconnect here
        if (protocol->mqtt_client != nullptr) {
            esp_mqtt_client_reconnect(protocol->mqtt_client);
        }
    }, self, pdMS_TO_TICKS(100)); // Delayed slightly to yield control
}

MqttProtocol::~MqttProtocol() {
    // Step 1: Stop and delete the reconnect timer
    if (reconnectTimer_ != nullptr) {
        xTimerStop(reconnectTimer_, portMAX_DELAY);
        xTimerDelete(reconnectTimer_, portMAX_DELAY);
        reconnectTimer_ = nullptr;
    }

    // Step 2: Reset UDP and MQTT communication resources
    // Assuming there's a method or logic to close connections and reset states
    udpSocket_.close();         // Hypothetical UDP socket wrapper
    mqttClient_.disconnect();   // Hypothetical MQTT client disconnection
    mqttClient_.reset();        // Clear internal state of MQTT client

    // Step 3: Release the event group associated with MQTT operations
    if (mqttEventGroup_ != nullptr) {
        vEventGroupDelete(mqttEventGroup_);
        mqttEventGroup_ = nullptr;
    }

    // Step 4: Mark the instance as inactive
    isActive_ = false;
}

#include "mqtt_client.h"
#include "cJSON.h"
#include "session_manager.h"
#include "audio_control.h"

// Global MQTT client instance
static esp_mqtt_client_handle_t mqtt_client = nullptr;

// Forward declarations of callback functions
static void mqtt_event_handler(void *handler_args, esp_event_base_t base, int32_t event_id, void *event_data);
static void handle_incoming_message(const char* topic, const char* payload, int len);
static void schedule_reconnect();

/**
 * @brief Starts the MQTT client with configuration and registers necessary event handlers.
 *
 * @param clean_session Boolean indicating whether to start with a clean session.
 */
void StartMqttClient(bool clean_session) {
    // Step 1: Configure MQTT Client
    const esp_mqtt_client_config_t mqtt_cfg = {
        .uri = CONFIG_MQTT_BROKER_URI,
        .username = CONFIG_MQTT_USERNAME,
        .password = CONFIG_MQTT_PASSWORD,
        .client_id = CONFIG_MQTT_CLIENT_ID,
        .keepalive = 60,
        .disable_clean_session = !clean_session,
    };

    // Step 2: Initialize MQTT Client
    mqtt_client = esp_mqtt_client_init(&mqtt_cfg);
    if (!mqtt_client) {
        ESP_LOGE("MQTT", "Failed to initialize MQTT client");
        return;
    }

    // Step 3: Register Event Handler
    esp_mqtt_client_register_event(mqtt_client, MQTT_EVENT_ANY, mqtt_event_handler, NULL);

    // Step 4: Start MQTT Client
    esp_err_t err = esp_mqtt_client_start(mqtt_client);
    if (err != ESP_OK) {
        ESP_LOGE("MQTT", "Failed to start MQTT client: %s", esp_err_to_name(err));
        schedule_reconnect();
        return;
    }

    ESP_LOGI("MQTT", "MQTT client started successfully.");
}

// Internal Callback for MQTT Events
static void mqtt_event_handler(void *handler_args, esp_event_base_t base, int32_t event_id, void *event_data) {
    esp_mqtt_event_handle_t event = (esp_mqtt_event_handle_t)event_data;

    switch (event->event_id) {
        case MQTT_EVENT_CONNECTED:
            ESP_LOGI("MQTT", "Connected to MQTT broker");
            break;

        case MQTT_EVENT_DISCONNECTED:
            ESP_LOGW("MQTT", "Disconnected from MQTT broker");
            schedule_reconnect();
            break;

        case MQTT_EVENT_DATA:
            handle_incoming_message(event->topic, event->data, event->data_len);
            break;

        default:
            break;
    }
}

// Handles Incoming Messages
static void handle_incoming_message(const char* topic, const char* payload, int len) {
    // Null-terminate payload for safe usage
    char* payload_str = (char*)malloc(len + 1);
    memcpy(payload_str, payload, len);
    payload_str[len] = '\0';

    cJSON *json = cJSON_Parse(payload_str);
    if (json == NULL) {
        ESP_LOGE("MQTT", "Invalid JSON in MQTT message");
        free(payload_str);
        return;
    }

    cJSON *cmd = cJSON_GetObjectItem(json, "command");
    if (cJSON_IsString(cmd)) {
        if (strcmp(cmd->valuestring, "start_session") == 0) {
            session_start();
        } else if (strcmp(cmd->valuestring, "stop_session") == 0) {
            session_stop();
        } else if (strcmp(cmd->valuestring, "play_audio") == 0) {
            cJSON *url = cJSON_GetObjectItem(json, "url");
            if (cJSON_IsString(url)) {
                play_audio_stream(url->valuestring);
            }
        }
    }

    cJSON_Delete(json);
    free(payload_str);
}

// Schedules a reconnect attempt after delay
static void schedule_reconnect() {
    static uint8_t retry_count = 0;
    const uint32_t max_delay_ms = 60000; // Max 60 seconds
    uint32_t delay = (1 << retry_count) * 1000; // Exponential backoff
    if (delay > max_delay_ms) delay = max_delay_ms;

    ESP_LOGI("MQTT", "Scheduling reconnect in %lu ms", delay);
    vTaskDelay(pdMS_TO_TICKS(delay));

    if (mqtt_client) {
        esp_mqtt_client_destroy(mqtt_client);
    }

    StartMqttClient(true); // Restart with clean session
}

bool MqttProtocol::SendText(const std::string& message) {
    // Step 1: Check if MQTT client is initialized and connected
    if (!mqtt_client_ || !mqtt_client_->IsConnected()) {
        LOG_ERROR("MQTT client not initialized or not connected.");
        server_error_state_ = true;
        return false;
    }

    // Step 2: Prepare payload (already a string, so direct usage)
    const std::string topic = "device/messages";  // Predefined topic

    // Step 3: Publish message to MQTT topic
    bool result = mqtt_client_->Publish(topic, message);

    // Step 4: Handle result
    if (!result) {
        LOG_ERROR("Failed to publish message to topic: %s", topic.c_str());
        server_error_state_ = true;
        return false;
    }

    // Success case
    return true;
}

