bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (!packet || packet->payload.empty()) {
        return false;
    }

    std::lock_guard<std::mutex> lock(_udp_mutex);  // Ensure thread safety

    // Update sequence number atomically or protected by mutex
    _sequence_number++;

    // Prepare Nonce for AES-CTR:
    // [4B SeqNum][4B Timestamp][4B PayloadSize] -> total 12 bytes
    union {
        struct {
            uint32_t sequence;
            uint32_t timestamp;
            uint32_t payload_size;
        } fields;
        uint8_t bytes[12];
    } nonce_data;

    nonce_data.fields.sequence = htonl(_sequence_number);
    nonce_data.fields.timestamp = htonl(packet->timestamp);
    nonce_data.fields.payload_size = htonl(static_cast<uint32_t>(packet->payload.size()));

    std::vector<uint8_t> encrypted_payload(packet->payload.size());

    // Perform AES-CTR Encryption
    if (!EncryptCTR(packet->payload.data(), packet->payload.size(),
                    _aes_key.data(), nonce_data.bytes,
                    encrypted_payload.data())) {
        SetError("Failed to encrypt audio payload");
        return false;
    }

    // Construct BinaryProtocol2 Header
    const size_t header_size = sizeof(BinaryProtocol2);
    const size_t full_packet_size = header_size + encrypted_payload.size();
    std::vector<uint8_t> udp_buffer(full_packet_size);

    auto* proto_header = reinterpret_cast<BinaryProtocol2*>(udp_buffer.data());
    proto_header->version = htons(2);               // Assuming version 2
    proto_header->type = htons(0);                  // Type 0 = OPUS
    proto_header->reserved = 0;
    proto_header->timestamp = htonl(packet->timestamp);
    proto_header->payload_size = htonl(static_cast<uint32_t>(encrypted_payload.size()));

    memcpy(proto_header->payload, encrypted_payload.data(), encrypted_payload.size());

    // Transmit over UDP
    if (!_udp_socket.Send(udp_buffer.data(), full_packet_size)) {
        SetError("UDP transmission failed");
        return false;
    }

    return true;
}

