void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Check if audio channel is actually open
    if (!IsAudioChannelOpened()) {
        return;
    }

    // Step 1: Reset the active UDP connection used for audio streaming
    if (udp_) {
        udp_.reset();
    }

    // Step 2: Construct and send a 'goodbye' message to the MQTT server
    if (mqtt_ && !publish_topic_.empty() && !session_id_.empty()) {
        cJSON* root = cJSON_CreateObject();
        cJSON_AddStringToObject(root, "type", "goodbye");
        cJSON_AddStringToObject(root, "session_id", session_id_.c_str());

        char* json_string = cJSON_PrintUnformatted(root);
        if (json_string) {
            mqtt_->Publish(publish_topic_, json_string);
            cJSON_free(json_string);
        }
        cJSON_Delete(root);
    }

    // Step 3: Trigger application-level callback to notify audio channel closure
    if (on_audio_channel_closed_) {
        on_audio_channel_closed_();
    }

    // Step 4: Update internal state to reflect that the audio channel is now inactive
    session_id_.clear();
    server_sample_rate_ = 24000;
    server_frame_duration_ = 60;
}

