bool MqttProtocol::OpenAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    if (IsAudioChannelOpened()) {
        return true;
    }

    // Reset sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Step 1: Initialize MQTT connection and send hello message
    if (!mqtt_ || !mqtt_->IsConnected()) {
        if (!StartMqttClient(true)) {
            SetError("Failed to start MQTT client");
            return false;
        }
    }

    // Send hello message
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        SetError("Failed to send hello message");
        return false;
    }

    // Step 2: Wait for server response and validate handshake
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,  // Clear bits on exit
        pdFALSE, // Wait for any bit
        pdMS_TO_TICKS(10000) // 10 second timeout
    );

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT)) {
        SetError("Timeout waiting for server hello response");
        return false;
    }

    // Step 3: Establish secure UDP socket for audio streaming
    if (!udp_) {
        SetError("UDP socket not initialized");
        return false;
    }

    if (!udp_->Connect(udp_server_, udp_port_)) {
        SetError("Failed to connect UDP socket");
        return false;
    }

    // Step 4: Start audio receiving thread/task
    // Note: This would typically start a separate task/thread to handle UDP packet reception
    // For now, we'll assume the infrastructure exists elsewhere

    // Notify that audio channel is opened
    if (on_audio_channel_opened_) {
        on_audio_channel_opened_();
    }

    return true;
}

