std::string MqttProtocol::GetHelloMessage() {
    // Create cJSON object for the hello message
    cJSON* root = cJSON_CreateObject();

    // Add basic message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add device identification
    cJSON_AddStringToObject(root, "device_id", SystemInfo::GetMacAddress().c_str());
    cJSON_AddStringToObject(root, "client_id", Board::GetInstance().GetUuid().c_str());

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", 1);

    // Create capabilities object
    cJSON* capabilities = cJSON_CreateObject();

    // Get AEC support status from AudioService
    bool aecSupported = AudioService::IsAecSupported();
    cJSON_AddBoolToObject(capabilities, "aec", aecSupported);

    // Get MCP support status from Board
    bool mcpSupported = Board::GetInstance().IsMcpSupported();
    cJSON_AddBoolToObject(capabilities, "mcp", mcpSupported);

    // Add other common capabilities
    cJSON_AddBoolToObject(capabilities, "encryption", true);
    cJSON_AddBoolToObject(capabilities, "udp", true);

    cJSON_AddItemToObject(root, "capabilities", capabilities);

    // Create audio configuration object
    cJSON* audio = cJSON_CreateObject();

    // Get audio parameters from AudioService
    AudioFormat format = AudioService::GetCurrentFormat();
    int sampleRate = AudioService::GetSampleRate();
    int frameDuration = AudioService::GetFrameDuration();
    int channels = AudioService::GetChannels();

    // Add audio parameters
    cJSON_AddStringToObject(audio, "format", 
        (format == AudioFormat::PCM) ? "pcm" : 
        (format == AudioFormat::OPUS) ? "opus" : "unknown");
    cJSON_AddNumberToObject(audio, "sample_rate", sampleRate);
    cJSON_AddNumberToObject(audio, "frame_duration", frameDuration);
    cJSON_AddNumberToObject(audio, "channels", channels);

    cJSON_AddItemToObject(root, "audio", audio);

    // Convert to string
    char* jsonString = cJSON_PrintUnformatted(root);
    std::string result(jsonString);

    // Clean up
    cJSON_free(jsonString);
    cJSON_Delete(root);

    return result;
}

