void Protocol::SendStartListening(ListeningMode mode) {
    // Step 1: Map ListeningMode enum to string
    const char* mode_str;
    switch (mode) {
        case kListeningModeAutoStop:
            mode_str = "auto";
            break;
        case kListeningModeManualStop:
            mode_str = "manual";
            break;
        case kListeningModeRealtime:
            mode_str = "realtime";
            break;
        default:
            SetError("Invalid ListeningMode");
            return;
    }

    // Step 2: Construct JSON object
    cJSON* json_root = cJSON_CreateObject();
    if (!json_root) {
        SetError("Failed to create JSON object");
        return;
    }

    cJSON_AddStringToObject(json_root, "session_id", session_id_.c_str());
    cJSON_AddStringToObject(json_root, "type", "listen");
    cJSON_AddStringToObject(json_root, "state", "start");
    cJSON_AddStringToObject(json_root, "mode", mode_str);

    // Step 3: Serialize to string
    char* json_text = cJSON_PrintUnformatted(json_root);
    if (!json_text) {
        cJSON_Delete(json_root);
        SetError("Failed to serialize JSON");
        return;
    }

    // Step 4: Transmit using SendText
    bool success = SendText(std::string(json_text));

    // Step 5: Clean up resources
    cJSON_Delete(json_root);
    free(json_text);

    // Step 6: Handle transmission error
    if (!success) {
        SetError("Failed to send start listening message");
    }
}

