extern void SendMessage(const std::string& message); // Communication interface
extern std::string GetSessionId();                   // Retrieve current session ID

using json = nlohmann::json;

void SendMcpMessage(const std::string& payload) {
    try {
        // Step 1: Construct JSON message with session ID and payload
        json message_json;
        message_json["sessionId"] = GetSessionId();
        message_json["payload"] = payload;

        // Step 2: Serialize the JSON object into a text string
        std::string serialized_message = message_json.dump();

        // Step 3: Send serialized message over communication channel
        SendMessage(serialized_message);
    } catch (const std::exception& e) {
        // Step 4: Handle potential errors during message construction or sending
