bool Protocol::IsTimeout() const {
    // Step 1: Get current time (assuming millisecond resolution)
    uint32_t current_time_ms = GetCurrentTimeMs();

    // Step 2: Calculate elapsed time since last incoming message
    uint32_t elapsed_time_ms = current_time_ms - last_incoming_timestamp_;

    // Step 3: Define timeout threshold (in milliseconds)
    const uint32_t TIMEOUT_THRESHOLD_MS = 120 * 1000; // 120 seconds

    // Step 4: Check for timeout
    if (elapsed_time_ms > TIMEOUT_THRESHOLD_MS) {
        // Step 5: Log error and return true
        ESP_LOGE("PROTOCOL", "Channel timeout detected: %u ms elapsed", elapsed_time_ms);
        return true;
    }

