bool WebsocketProtocol::Start() {
    // Initialize WebSocket client and configure connection parameters
    auto& board = Board::GetInstance();
    auto network = board.GetNetworkInterface();

    // Check if network is connected
    if (!network->IsConnected()) {
        ESP_LOGE(TAG, "Network is not connected, cannot start WebSocket");
        return false;
    }

    // Get WebSocket configuration from OTA settings
    std::string server_url = ota_->GetWebsocketUrl();
    if (server_url.empty()) {
        ESP_LOGE(TAG, "WebSocket URL is not configured");
        return false;
    }

    // Create WebSocket client configuration
    esp_websocket_client_config_t ws_cfg = {};
    ws_cfg.uri = server_url.c_str();
    ws_cfg.disable_auto_reconnect = false;
    ws_cfg.pingpong_timeout_sec = 10;
    ws_cfg.network_timeout_ms = 10000;
    ws_cfg bufferSize = 4096;

    // Add authentication headers if needed
    std::string auth_token = ota_->GetAuthToken();
    if (!auth_token.empty()) {
        ws_cfg.headers = "Authorization: Bearer ";
        ws_cfg.headers += auth_token;
    }

    // Create WebSocket client
    client_ = esp_websocket_client_init(&ws_cfg);
    if (!client_) {
        ESP_LOGE(TAG, "Failed to initialize WebSocket client");
        return false;
    }

    // Register event handlers
    esp_websocket_register_events(client_, WEBSOCKET_EVENT_CONNECTED, 
                                  websocket_event_handler, this);
    esp_websocket_register_events(client_, WEBSOCKET_EVENT_DISCONNECTED, 
                                  websocket_event_handler, this);
    esp_websocket_register_events(client_, WEBSOCKET_EVENT_DATA, 
                                  websocket_event_handler, this);
    esp_websocket_register_events(client_, WEBSOCKET_EVENT_ERROR, 
                                  websocket_event_handler, this);

    // Start WebSocket connection in background
    esp_err_t err = esp_websocket_client_start(client_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start WebSocket client: %s", esp_err_to_name(err));
        esp_websocket_client_destroy(client_);
        client_ = nullptr;
        return false;
    }

    ESP_LOGI(TAG, "WebSocket connection initiated to %s", server_url.c_str());
    return true;
}

