bool WebSocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Step 1: Check WebSocket connection status and audio channel state
    if (!IsWebSocketConnected() || !IsAudioChannelOpened()) {
        SetError("WebSocket is not connected or audio channel is closed");
        return false;
    }

    // Step 2: Determine negotiated protocol version
    // Assuming protocol_version_ is set upon connection negotiation
    const int kProtocolV2 = 2;
    const int kProtocolV3 = 3;

    std::vector<uint8_t> buffer;

    switch (protocol_version_) {
        case kProtocolV2: {
            // BinaryProtocol2 format:
            // [version(2)][type(2)][reserved(4)][timestamp(4)][payload_size(4)][payload...]

            BinaryProtocol2 header{};
            header.version = htons(kProtocolV2);
            header.type = htons(0); // OPUS
            header.reserved = htonl(0);
            header.timestamp = htonl(packet->timestamp);
            header.payload_size = htonl(static_cast<uint32_t>(packet->payload.size()));

            const size_t header_size = sizeof(BinaryProtocol2);
            const size_t total_size = header_size + packet->payload.size();

            buffer.resize(total_size);
            memcpy(buffer.data(), &header, header_size);
            memcpy(buffer.data() + header_size, packet->payload.data(), packet->payload.size());
            break;
        }

        case kProtocolV3: {
            // BinaryProtocol3 format:
            // [type(1)][reserved(1)][payload_size(2)][payload...]

            if (packet->payload.size() > UINT16_MAX) {
                SetError("Payload too large for protocol v3");
                return false;
            }

            BinaryProtocol3 header{};
            header.type = 0; // OPUS
            header.reserved = 0;
            header.payload_size = htons(static_cast<uint16_t>(packet->payload.size()));

            const size_t header_size = sizeof(BinaryProtocol3);
            const size_t total_size = header_size + packet->payload.size();

            buffer.resize(total_size);
            memcpy(buffer.data(), &header, header_size);
            memcpy(buffer.data() + header_size, packet->payload.data(), packet->payload.size());
            break;
        }

        default: {
            // Raw mode: just send the payload directly
            buffer = std::move(packet->payload);
            break;
        }
    }

    // Step 3: Transmit the formatted packet over WebSocket
    // Assume existence of a protected method SendBinary() in base class
    if (!SendBinary(buffer)) {
        SetError("Failed to send audio packet over WebSocket");
        return false;
    }

    return true;
}

bool WebSocketProtocol::SendText(const std::string& message) {
    // Step 1: Check if WebSocket is connected
    if (!_websocketClient.IsConnected()) {
        LogError("WebSocket is not connected. Cannot send text message.");
        return false;
    }

    // Step 2: Prepare and encode the message as a WebSocket text frame
    std::vector<uint8_t> frame;
    try {
        frame = EncodeTextFrame(message); // Assumes helper function exists
    } catch (const std::exception& e) {
        LogError("Failed to encode text frame: " + std::string(e.what()));
        SetServerErrorState(); // Notify higher-level system of issue
        return false;
    }

    // Step 3: Attempt to send the encoded frame
    if (!_websocketClient.SendFrame(frame)) {
        LogError("Failed to send WebSocket text frame.");
        SetServerErrorState(); // Update server state due to communication error
        return false;
    }

    // Success case
    return true;
}

