bool WebsocketProtocol::OpenAudioChannel() {
    // Configure WebSocket authentication headers and protocol version
    std::map<std::string, std::string> headers;
    headers["Authorization"] = "Bearer " + GetAuthToken();
    headers["X-Protocol-Version"] = "3"; // Use latest protocol version

    // Set device identifiers and establish WebSocket connection
    std::string device_id = GetDeviceId();
    std::string url = GetWebSocketUrl() + "/audio?device_id=" + device_id;

    // Create WebSocket client with headers
    websocket_client_ = std::make_unique<WebSocketClient>(url, headers);

    if (!websocket_client_ || !websocket_client_->Connect()) {
        SetError("Failed to establish WebSocket connection");
        return false;
    }

    // Define binary packet handler for incoming audio data
    websocket_client_->SetBinaryMessageHandler([this](const uint8_t* data, size_t length) {
        if (length < sizeof(uint8_t)) {
            return;
        }

        // Determine protocol version from first byte
        uint8_t version = data[0] >> 4;

        if (version == 2 && length >= sizeof(BinaryProtocol2)) {
            // Parse audio stream packets with protocol v2 support
            const BinaryProtocol2* packet = reinterpret_cast<const BinaryProtocol2*>(data);

            // Handle byte order conversion and payload extraction
            uint16_t type = ntohs(packet->type);
            uint32_t timestamp = ntohl(packet->timestamp);
            uint32_t payload_size = ntohl(packet->payload_size);

            if (payload_size > 0 && sizeof(BinaryProtocol2) + payload_size <= length) {
                if (type == 0) { // OPUS audio data
                    auto audio_packet = std::make_unique<AudioStreamPacket>();
                    audio_packet->sample_rate = server_sample_rate_;
                    audio_packet->frame_duration = server_frame_duration_;
                    audio_packet->timestamp = timestamp;
                    audio_packet->payload.assign(packet->payload, packet->payload + payload_size);

                    if (on_incoming_audio_) {
                        on_incoming_audio_(std::move(audio_packet));
                    }
                } else if (type == 1) { // JSON data
                    std::string json_str(reinterpret_cast<const char*>(packet->payload), payload_size);
                    cJSON* json = cJSON_Parse(json_str.c_str());
                    if (json && on_incoming_json_) {
                        on_incoming_json_(json);
                    }
                    if (json) {
                        cJSON_Delete(json);
                    }
                }
            }
        } else if (version == 3 && length >= sizeof(BinaryProtocol3)) {
            // Parse audio stream packets with protocol v3 support
            const BinaryProtocol3* packet = reinterpret_cast<const BinaryProtocol3*>(data);

            // Handle byte order conversion and payload extraction
            uint16_t payload_size = ntohs(packet->payload_size);

            if (payload_size > 0 && sizeof(BinaryProtocol3) + payload_size <= length) {
                if (packet->type == 0) { // OPUS audio data
                    auto audio_packet = std::make_unique<AudioStreamPacket>();
                    audio_packet->sample_rate = server_sample_rate_;
                    audio_packet->frame_duration = server_frame_duration_;
                    audio_packet->timestamp = 0; // V3 doesn't include timestamp
                    audio_packet->payload.assign(packet->payload, packet->payload + payload_size);

                    if (on_incoming_audio_) {
                        on_incoming_audio_(std::move(audio_packet));
                    }
                } else if (packet->type == 1) { // JSON data
                    std::string json_str(reinterpret_cast<const char*>(packet->payload), payload_size);
                    cJSON* json = cJSON_Parse(json_str.c_str());
                    if (json && on_incoming_json_) {
                        on_incoming_json_(json);
                    }
                    if (json) {
                        cJSON_Delete(json);
                    }
                }
            }
        }
    });

    // Set up connection event handlers
    websocket_client_->SetConnectionOpenHandler([this]() {
        if (on_audio_channel_opened_) {
            on_audio_channel_opened_();
        }
    });

    websocket_client_->SetConnectionCloseHandler([this]() {
        if (on_audio_channel_closed_) {
            on_audio_channel_closed_();
        }
    });

