        SetError(error);
        if (on_network_error_) {
            on_network_error_(error);
        }
    });

    // Validate and return connection success status
    bool is_connected = websocket_client_->IsConnected();
    if (is_connected) {
        // Start the WebSocket client loop in a separate thread
        websocket_thread_ = std::thread([this]() {
            while (websocket_client_ && websocket_client_->IsConnected()) {
                websocket_client_->Poll();
                std::this_thread::sleep_for(std::chrono::milliseconds(10));
            }
