std::string WebsocketProtocol::GetHelloMessage() {
    // Create JSON root object
    cJSON* root = cJSON_CreateObject();

    // Add message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", version_);

    // Add features object
    cJSON* features = cJSON_CreateObject();
    cJSON_AddBoolToObject(features, "aec", true);  // Assuming AEC is supported
    cJSON_AddBoolToObject(features, "mcp", true);  // Assuming MCP is supported
    cJSON_AddItemToObject(root, "features", features);

    // Add transport information
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio configuration
    cJSON* audio = cJSON_CreateObject();
    cJSON_AddStringToObject(audio, "format", "pcm");  // Common audio format
    cJSON_AddNumberToObject(audio, "rate", 16000);    // Standard sample rate
    cJSON_AddNumberToObject(audio, "channels", 1);    // Mono channel
    cJSON_AddNumberToObject(audio, "frame_duration", 20); // 20ms frame duration
    cJSON_AddItemToObject(root, "audio", audio);

    // Serialize to string
    char* json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string);

    // Clean up
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

