ParseResult ParseServerHello(const cJSON *json_root) {
    if (!cJSON_IsObject(json_root)) {
        return PARSE_ERROR_INVALID_JSON;
    }

    const cJSON *transport_item = cJSON_GetObjectItemCaseSensitive(json_root, "transport");
    if (!cJSON_IsString(transport_item) || strcmp(transport_item->valuestring, "websocket") != 0) {
        return PARSE_ERROR_UNSUPPORTED_TRANSPORT;
    }

    const cJSON *session_id_item = cJSON_GetObjectItemCaseSensitive(json_root, "session_id");
    if (!cJSON_IsString(session_id_item)) {
        return PARSE_ERROR_MISSING_FIELD;
    }
    strncpy(g_session_id, session_id_item->valuestring, sizeof(g_session_id) - 1);
    g_session_id[sizeof(g_session_id) - 1] = '\0'; // Ensure null termination

    const cJSON *sample_rate_item = cJSON_GetObjectItemCaseSensitive(json_root, "sample_rate");
    if (!cJSON_IsNumber(sample_rate_item)) {
        return PARSE_ERROR_MISSING_FIELD;
    }
    g_sample_rate = static_cast<uint32_t>(sample_rate_item->valuedouble);

    const cJSON *frame_duration_item = cJSON_GetObjectItemCaseSensitive(json_root, "frame_duration");
    if (!cJSON_IsNumber(frame_duration_item)) {
        return PARSE_ERROR_MISSING_FIELD;
    }
    g_frame_duration = static_cast<uint32_t>(frame_duration_item->valuedouble);

    // Signal that parsing was successful and device is ready for streaming
    // Assuming FreeRTOS xEventGroupSetBits or similar mechanism
    if (g_event_group != nullptr) {
        // Example: xEventGroupSetBits((EventGroupHandle_t)g_event_group, SERVER_HELLO_PARSED_BIT);
        // For portability, simulate setting bit here
        // Actual implementation depends on RTOS/environment
    }

    return PARSE_OK;
}
